	public function getChatStudentListHtml(Request $request){
		$user = Auth::user();
		$user_id = $user->id;
		$institute_id = $user->institute_id;
		$userTimeZone = !empty($user->time_zone) ? $user->time_zone : Config::get('app.timezone');
		$academic_session_id =  Session::get('aSessionId');		
	    $semester_id =  Session::get('semesterId');
		$tutorName = $user->fullname;
		
		
		$tutorGradeSection = DB::table('member_section')
							->select('member_section.user_id as tutor_id', 'grades.school_id', 'member_section.grade_id', 'member_section.section_id', 'school_name', DB::raw('CONCAT(grades.grade, " (", section.section, ")") AS grade_section'))
							->Join('grades', function ($join) use ($academic_session_id, $semester_id) {
							$join->on('grades.id', '=', 'member_section.grade_id')
								->where('member_section.academic_session_id', $academic_session_id)
								->where('member_section.semester_id', $semester_id)
								->where('member_section.status', 1);
							})
							->join('school', 'grades.school_id', '=', 'school.id')
							->join('section', 'member_section.section_id', '=', 'section.id')
							->where('member_section.user_id', '=', $user_id)
							->where('school.institute_id', '=', $institute_id)
							->where('school.status', '=', 1)
							->get();
							
		
		$mainGroupArr =array();
		$studentsArr= array();	
		$groupsArr = array();
			
		if(!empty($tutorGradeSection)){
			foreach ($tutorGradeSection as $key => $tutorGradeSectionVal) {
				
				$main_group_id = base64_encode($tutorGradeSectionVal->school_id.'-'.$tutorGradeSectionVal->grade_id.'-'.$tutorGradeSectionVal->section_id.'-'.$tutorGradeSectionVal->tutor_id);
				$last_msg_info = DB::table('chat_msg as c')
								->select('c.id as chat_id', 'c.group_id', 'c.sender_id', 'c.msg','c.created_at','c.is_share_file','c.is_link','chat_shared_file.file_type','chat_shared_file.file_name','chat_shared_file.file_mime_type','chat_shared_file.is_recording','chat_shared_file.recording_duration')
								->leftJoin('chat_shared_file','chat_shared_file.chat_id', '=', 'c.id')
								->where('c.group_id', '=', $main_group_id)
								->where('c.institute_id', $institute_id)
								->where('c.academic_session_id', $academic_session_id)
								->where('c.semester_id', $semester_id)
								->orderBy('c.id', 'DESC')
								->first();
				$mainGroupArr[$key] = new \stdClass(); //the magic see new object member created on the fly without warning.
				$mainGroupArr[$key]->id = $tutorGradeSectionVal->tutor_id;
				$mainGroupArr[$key]->main_group_id = $main_group_id;
				$mainGroupArr[$key]->group_name = $tutorGradeSectionVal->grade_section;
				$mainGroupArr[$key]->group_image = url('/').'/public/uploads/icon/icon_1644316802.png';
				$mainGroupArr[$key]->school_id = $tutorGradeSectionVal->school_id;	
				$mainGroupArr[$key]->grade_id =  $tutorGradeSectionVal->grade_id;
				$mainGroupArr[$key]->section_id = $tutorGradeSectionVal->section_id;
				$mainGroupArr[$key]->chat_id = !empty($last_msg_info->chat_id) ? $last_msg_info->chat_id : '';	
				$mainGroupArr[$key]->msg = !empty($last_msg_info->msg) ? $last_msg_info->msg : '';	
				$mainGroupArr[$key]->time = !empty($last_msg_info->created_at) ? Helper::getTime(Carbon::createFromFormat('Y-m-d H:i:s', $last_msg_info->created_at, 'UTC')->setTimezone($userTimeZone)->format('h:i A')) : ''; 	
				$mainGroupArr[$key]->file_type = !empty($last_msg_info->file_type) ? $last_msg_info->file_type : '';	
				$mainGroupArr[$key]->file_name = !empty($last_msg_info->file_name) ? $last_msg_info->file_name : '';	
				$mainGroupArr[$key]->file_mime_type = !empty($last_msg_info->file_mime_type) ? $last_msg_info->file_mime_type : '';	
				$mainGroupArr[$key]->is_recording = !empty($last_msg_info->is_recording) ? $last_msg_info->is_recording : '';
				$mainGroupArr[$key]->recording_duration = !empty($last_msg_info->recording_duration) ? $last_msg_info->recording_duration : '';

				
				$groupsArr[] = array('institute_id'=>$institute_id,
									 'group_id'=>$main_group_id,	
									 'group_name'=>$tutorGradeSectionVal->grade_section.'-('.ucfirst($tutorName).')',
									 'group_image'=>url('/').'/public/uploads/icon/icon_1644316802.png',										 
									 'chat_type'=>2,	
									 'status'=>1,	
									 'created_at' => date('Y-m-d H:i:s'),
									);
									
				$students = DB::table('users')
								->select('users.id as student_id', 'users.fullname', 'users.profile_pic', 'users.is_login', 'grades.school_id', 'member_section.grade_id', 'member_section.section_id')
								->join('member_section', function ($join) use ($tutorGradeSectionVal,$academic_session_id,$semester_id){
									$join->on('member_section.user_id', '=', 'users.id')
										->where('member_section.status', '=', 1)
										->where('member_section.academic_session_id', $academic_session_id)
										->where('member_section.semester_id', $semester_id)
										->where('member_section.section_id', '=', $tutorGradeSectionVal->section_id);
								})
								->join('member_grade', function ($join) use ($tutorGradeSectionVal,$academic_session_id,$semester_id) {
									$join->on('member_grade.user_id', '=', 'users.id')
										->where('member_grade.academic_session_id', $academic_session_id)
										->where('member_grade.semester_id', $semester_id)
										->where('member_grade.status', '=', 1)
										->where('member_grade.grade_id', '=', $tutorGradeSectionVal->grade_id);
								})
								->join('grades', function ($join) use ($tutorGradeSectionVal) {
									$join->on('grades.id', '=', 'member_grade.grade_id')
										->where('grades.school_id', '=', $tutorGradeSectionVal->school_id);
								})
								->where('users.role_id', '=', 3)
								->where('users.institute_id', '=', $institute_id)
								->orderBy('users.first_name', 'ASC')
								->get()
								->all();
							
				if(!empty($students)){
					foreach ($students as $key => $studentsVal) {
						$groupID =  base64_encode($studentsVal->school_id.'-'.$studentsVal->grade_id.'-'.$studentsVal->section_id.'-'.$studentsVal->student_id.'-'.$user_id);
						$last_msg_info = DB::table('chat_msg as c')
										->select('c.id as chat_id', 'c.group_id', 'c.sender_id', 'c.msg', 'c.created_at','c.is_share_file','c.is_link','chat_shared_file.file_type','chat_shared_file.file_name','chat_shared_file.file_mime_type','chat_shared_file.is_recording','chat_shared_file.recording_duration')
										->leftJoin('chat_shared_file','chat_shared_file.chat_id', '=', 'c.id')
										->where('c.group_id', '=', $groupID)
										->where('c.institute_id', $institute_id)
										->where('c.academic_session_id', $academic_session_id)
										->where('c.semester_id', $semester_id)
										->orderBy('c.id', 'DESC')
										->first();
						$studentsVal->main_group_id = '';	
						$studentsVal->school_id = $tutorGradeSectionVal->school_id;	
						$studentsVal->grade_id =  $tutorGradeSectionVal->grade_id;
						$studentsVal->section_id = $tutorGradeSectionVal->section_id;	
						$studentsVal->chat_id = !empty($last_msg_info->chat_id) ? $last_msg_info->chat_id : '';	
						$studentsVal->msg = !empty($last_msg_info->msg) ? $last_msg_info->msg : '';	
						$studentsVal->time = !empty($last_msg_info->created_at) ? Helper::getTime(Carbon::createFromFormat('Y-m-d H:i:s', $last_msg_info->created_at, 'UTC')->setTimezone($userTimeZone)->format('h:i A')) : ''; 	
						$studentsVal->group_id = $groupID;	
						$studentsVal->file_type = !empty($last_msg_info->file_type) ? $last_msg_info->file_type : '';	
						$studentsVal->file_name = !empty($last_msg_info->file_name) ? $last_msg_info->file_name : '';	
						$studentsVal->file_mime_type = !empty($last_msg_info->file_mime_type) ? $last_msg_info->file_mime_type : '';	
						$studentsVal->is_recording = !empty($last_msg_info->is_recording) ? $last_msg_info->is_recording : '';	
						$studentsVal->recording_duration = !empty($last_msg_info->recording_duration) ? $last_msg_info->recording_duration : '';	
						//array_push($mainGroupArr,$studentsVal);
						$studentsArr[] = $studentsVal;
						
						$groupsArr[] = array('institute_id'=>$institute_id,
										 'group_id'=>$groupID,	
										 'group_name'=>ucfirst($tutorName).'-'.ucfirst($studentsVal->fullname),	
										 'group_image'=>!empty($studentsVal->profile_pic) ? $studentsVal->profile_pic :'',	
										 'chat_type'=>1,	
										 'status'=>1,	
										 'created_at' => date('Y-m-d H:i:s'),
										);
					}
				}
					
			}
		}
		if(!empty($groupsArr)){
			DB::table('chat_group')->insertOrIgnore($groupsArr);
		}
		$mainGroup = array_merge($studentsArr,$mainGroupArr);
		$studentData = collect($mainGroup)->sortByDesc('chat_id')->values();
		$data['studentData'] = $studentData; 
		$data['user_id'] = $user_id; 
		
		$returnHTML = view('tutor/_student_list_chat')->with($data)->render();
        return response()->json(['status' => true,'returnHTML'=>$returnHTML,'studentData'=>$studentData]);
        die;
    }
			
