	public function getChatConversation(Request $request){
		$user = Auth::user();
		$user_id = $user->id;
		$institute_id = $user->institute_id;
		$userTimeZone = !empty($user->time_zone) ? $user->time_zone : Config::get('app.timezone');
		$academic_session_id =  Session::get('aSessionId');		
	    $semester_id =  Session::get('semesterId');
		
		
        $group_id = $request->group_id;
        $student_id = $request->student_id;
        $active_group_id = $request->active_group_id;
		$is_click = $request->is_click;
      
        $grpmsgs = DB::table('chat_msg as c')
                ->select('c.id as chat_id', 'c.group_id', 'c.sender_id', 'c.msg','c.created_at','c.is_share_file', 'c.is_link','c.is_meet_in_classroom','c.file_type','c.mime_type','c.is_reply','c.reply_message_id','c.reply_share_message_id','c.is_forward','c.track_duration','users.id','users.profile_pic','users.fullname as sender_name')
                ->Join('users', 'users.id', '=', 'c.sender_id')
                ->where('c.group_id', '=', $active_group_id)
                ->where('c.institute_id', '=', $institute_id)
                ->where('c.academic_session_id', '=', $academic_session_id)
                ->where('c.semester_id', '=', $semester_id)
                ->orderBy('chat_id', 'DESC')
				->limit(10)
			    ->get()
				->reverse();
	            $allowedImg = array('gif', 'png', 'jpg','jpeg');
				$allowedAudio = array('mp4', 'wav','ogg','mp3','webm','wmv');
				$allowedDoc = array('pdf','ppt','pptm','pptx', 'excel','doc','docx','docm','txt','zip');
				$return_view = "";
        if (!empty($grpmsgs)) {
			
			$dateGroupByday ="";
			
			foreach ($grpmsgs as $k1 => $v1) {
				
				$sender_name = "'".trim($v1->sender_name)."'";
				$message = "'".trim($v1->msg)."'";
				$isforward="";
				$isforwardIcon="";
				$isfileClass="";
				$chat_shared_file_id = "''";
				$mutlipleMediasharefile ="";
				
				$dateTime = Carbon::createFromFormat('Y-m-d H:i:s', $v1->created_at, 'UTC')
							->setTimezone($userTimeZone)
							->format('d-m-Y h:i A');
				$date_time = Helper::getDatetime($dateTime);
				
				if(!empty($v1->is_forward)){
				  $isforwardIcon = '<a class="frWrdtOP" href="javascript:void(0)"><i class="fa fa-share" aria-hidden="true"></i>Forwarded</a>';	
				}
				$track_duration = !empty($v1->track_duration) ? $v1->track_duration : '';
			    
				if ($v1->sender_id == $user_id) {
					if (!empty($v1->profile_pic)) {
						$path = parse_url($v1->profile_pic);
						if(isset($path['scheme']) == 'https' || isset($path['scheme']) == 'http'){
