	public function getChatLoadMore(Request $request){
		$locale = Session::get('locale');
		$user = Auth::user();
		$user_id = $user->id;
		$institute_id = $user->institute_id;
		$userTimeZone = !empty($user->time_zone) ? $user->time_zone : Config::get('app.timezone');
		
		$academic_session_id =  Session::get('aSessionId');		
	    $semester_id =  Session::get('semesterId');
		
		$chat_serach_txt = $request->chat_serach_txt;
        $active_group_id = $request->active_group_id;
        $group_id = $request->group_id;
        $groupchat_id = $request->groupchat_id;
        $gradesection_group_id = $request->gradesection_group_id;
        $page = $request->page; 
		$page = $request->page ? $request->page : 1;
        $limit = 10;
		
        $grpmsgs = DB::table('chat_msg as c')
                ->select('c.id as chat_id', 'c.group_id', 'c.sender_id', 'c.msg','c.created_at', 'c.is_share_file', 'c.is_link','c.file_type','c.mime_type','c.is_reply','c.reply_message_id','c.reply_share_message_id','c.track_duration','c.is_name_header','users.id','users.profile_pic','users.fullname as sender_name')
                ->join('chat_msg_status', 'c.id', '=', 'chat_msg_status.chat_msg_id')
				->join('users', 'users.id', '=', 'c.sender_id')
                ->where('c.group_id', '=', $active_group_id)
				->where('c.institute_id', '=', $institute_id)
				->where('c.academic_session_id', '=', $academic_session_id)
				->where('c.semester_id', '=', $semester_id)
				->Where(function ($query) use ($chat_serach_txt) {
					if(!empty($chat_serach_txt)){
						$query->Where('c.msg', 'like', '%' . $chat_serach_txt . '%');
					} 
				})
			    ->groupBy('chat_id')
			    ->orderBy('chat_id', 'DESC')
				->limit($limit)
				->offset(($page - 1) * $limit)
                ->get()
				->reverse();
	
	    $return_view = "";
		$allowedImg = array('gif', 'png', 'jpg','jpeg');
		$allowedAudio = array('mp4', 'wav','ogg','mp3');
		
        if ($grpmsgs->count() > 0) {
			
			foreach ($grpmsgs as $k1 => $v1) {
				
				$sender_name = "'".trim($v1->sender_name)."'";
				$message = "'".trim($v1->msg)."'";
				$isforward="";
				$isforwardIcon="";
				$isfileClass="";
