	public function shareFileMedia(Request $request) {
		$locale = Session::get('locale');
		
		$user = Auth::user();
		$user_id = $user->id;
		$institute_id = $user->institute_id;
		$userTimeZone = !empty($user->time_zone) ? $user->time_zone : Config::get('app.timezone');
		
		$academic_session_id =  Session::get('aSessionId');		
	    $semester_id =  Session::get('semesterId'); 
		
		$group_id = $request->input('group_id');
		$groupchat_id = $request->input('groupchat_id');
		$gradesection_group_id = $request->input('gradesection_group_id');
		$b2c_group_id = $request->input('b2c_group_id');
		
		$message = trim($request->input('txt_message'));
		$recevier_id = $request->input('recevier_id');

		$date_time = $request->input('date_time');
		$currentDateTime = Carbon::now($userTimeZone)->format('Y-m-d H:i:s');
		$utcCurrentDateTime = Carbon::createFromFormat('d-M-Y h:i a',trim($date_time), $userTimeZone)->setTimezone('UTC')->format('Y-m-d H:i:s');
		
		$active_group_id = $request->input('active_group_id');
		$active_file = $request->input('active_file');
		$sender_name = "'".Auth::user()->first_name."'";	
		$recevierIdArr = explode(",",$recevier_id);
		$groupIdArr = explode(",",$group_id);
		$allowedAudio = array('mp4', 'wav','ogg','mp3','webm','wmv');
		$randomIdArr = explode(",",$request->input('random_id'));
		$flage = true;
		$share_fileArr = array();	
		
		$imgArr = array();
		 if ($request->hasfile('file')) {
			foreach($request->file('file') as $file) {
				$file_name = $file->getClientOriginalName();
				$file_mime_type = $file->getClientMimeType();
				$upload_path = public_path().'/uploads/chat_share_file/';
				if (!file_exists($upload_path)) {
					mkdir($upload_path, 0777, true);
				}
				if (strcmp($active_file, $file_name) == 0) {
					  $is_active_file = 1;
				}else {
					   $is_active_file = 0;
				}
				$file->move($upload_path, $file_name);
				$videotoimg="";
				if(strstr($file_mime_type, "video/")){
					  $videotoimg = Helper::videotoImg($file_name);
				}
				$imgArr[] = array('file_name'=>$file_name,'file_mime_type'=>$file_mime_type,'file_type'=>2,'is_active_file'=>$is_active_file,'other_file'=>$videotoimg,'created_date'=> $utcCurrentDateTime);
			}
		} 
		
		$senderArr = array('sender_id' => $user_id ,
							'institute_id' => $institute_id ,
							'academic_session_id' => $academic_session_id ,
							'semester_id' => $semester_id ,
							'msg' => $message,
							'is_share_file' => 1,
							'file_type' =>2,
							'status' => 1,
							'created_at' => $utcCurrentDateTime,
							);
					if(!empty($reply_message_id)){
						$senderArr['is_reply']=1;
						$senderArr['reply_message_id']= $reply_message_id;
						if(!empty($reply_share_message_id)){
							$senderArr['reply_share_message_id'] = $reply_share_message_id;
						}
					}
		$groupMember="";
		if(!empty($gradesection_group_id) && empty($group_id) && empty($groupchat_id)){
					if(!empty($recevier_id)){
						$senderArr['group_id'] = $gradesection_group_id;
						$senderArr['is_name_header']= 1;
						$insert_Id = DB::table('chat_msg')->insertGetId($senderArr);
							if($insert_Id){
								foreach($recevierIdArr as $key=>$recevierIdArrVal){
									$chatMsgStatus = array(
										'receiver_id' => $recevierIdArrVal,
										'chat_msg_id' =>$insert_Id,
										'is_read' => 0,
										'status' => 0,
										'chat_msg_type' =>1,
										'created_at' => $utcCurrentDateTime,
									);
								   DB::table('chat_msg_status')->insert($chatMsgStatus);
								}
								if(!empty($imgArr)){
									foreach($imgArr as $key => $csm){
									  $imgArr[$key]['chat_id'] = $insert_Id;
									}
								 DB::table('chat_shared_file')->insert($imgArr);	
								}
							}
					}
		}
