				if(!empty($groupMember)){
					foreach($groupMember as $key=>$group_memberVal){
						
						$total_message = Helper::getMessageCount($group_memberVal->user_id); 
						$total_group_message = Helper::getMessageCountByUserGroupsChat($group_memberVal->user_id,$groupchat_id); 
						$totalMessage[] = array('total_message'=>$total_message,
												'receiver_id'=>$group_memberVal->user_id,
												'total_group_message'=>$total_group_message,
												'cgi'=>$group_memberVal->group_id,
											   );
					}
				}
				$msgsend =  array('totalMessage'=>$totalMessage,
									'cgroupcode'=>$groupchat_id,
									'sender_id'=>$user_id,
									'gid'=>$active_group_id,
									'chatboxmsgid'=>base64_decode($active_group_id),
									'chat_id'=>$chat_id,
									'update_message_id'=>'',
									'remove_message_id'=>'',
									'remove_bulk_message_id'=>'',
									'message_type'=>'groupschat');
			}
			elseif(!empty($b2c_group_id) && empty($group_id) && empty($gradesection_group_id) && empty($groupchat_id) ){
					$totalMessage =	Helper::getMessageCount($recevier_id);
					$msgsend =  array('totalMessage'=>$totalMessage,
									  'gid'=>$b2c_group_id,
									  'receiver_id'=>$recevier_id,
									  'sender_id'=>$user_id,
									  'chatboxmsgid'=>base64_decode($active_group_id),
									  'chat_id'=>$chat_id,
									  'update_message_id'=>'',
									  'remove_message_id'=>'',
									  'remove_bulk_message_id'=>'',
									  'chat_message'=>$chat_message,
									  'message_type'=>'b2c'
									);                              
				}
			else{
				$message_type='';	
			
				if(!empty($recevierIdArr)){
					foreach($recevierIdArr as $key=>$recevierId){
						
						$total_message = Helper::getMessageCount($recevierId); 
						$total_group_message = Helper::getMessageCountByUser($recevierId,$user_id); 
						
						$totalMessage[] = array('total_message'=>$total_message,
												'receiver_id'=>$recevierId,
												'total_group_message'=>$total_group_message,
												'chat_message'=>$chat_message,
												'last_message'=>$last_message,
												'message_time'=>$message_time,
											   );
					}
				}
				$msgsend =  array('totalMessage'=>$totalMessage,
								  'sender_id'=>$user_id,
								  'gid'=>$active_group_id,
								  'chatboxmsgid'=>base64_decode($active_group_id),
								  'chat_id'=>$chat_id,
								  'remove_bulk_message_id'=>'',
								  'remove_message_id'=>'',
								  'update_message_id'=>'',
								  'forward_file'=>true); 
								  
				foreach(array_chunk($msgsend, 2) as $curta ) {
					event(new ChatMessage($curta));
				}
				
			}
			event(new ChatMessage($msgsend));
			return response()->json(['status' => true,'id' =>$chat_id,'fileName' =>$last_message,'share_file'=>$share_file,'path' => url('/download').'/'.$chat_id,'update_message_id' =>'','remove_message_id'=>'','remove_bulk_message_id'=>'','message_type'=>$message_type]);
	}
    	
    public function replayShareFileMedia(Request $request) {
		$locale = Session::get('locale');
		
		$user = Auth::user();
		$user_id = $user->id;
		$institute_id = $user->institute_id;
		$userTimeZone = !empty($user->time_zone) ? $user->time_zone : Config::get('app.timezone');
		
		$academic_session_id =  Session::get('aSessionId');		
	    $semester_id =  Session::get('semesterId'); 
		
		
		$recevier_id = $request->input('recevier_id');
		$group_id = $request->input('group_id');
		$groupchat_id = $request->input('groupchat_id');
		$gradesection_group_id = $request->input('gradesection_group_id');
		$b2c_group_id = $request->input('b2c_group_id');
		
		$date_time = $request->input('date_time');
		$currentDateTime = Carbon::now($userTimeZone)->format('Y-m-d H:i:s');
		$utcCurrentDateTime = Carbon::createFromFormat('Y-m-d H:i:s',trim($currentDateTime), $userTimeZone)->setTimezone('UTC')->format('Y-m-d H:i:s');
		
		$active_group_id = $request->input('active_group_id');
		$message = trim($request->input('txt_message'));
		$active_file = $request->input('active_file');
		$reply_message_id = $request->input('reply_message_id');
		$reply_share_message_id = $request->input('reply_share_message_id');
		$track_duration = $request->input('track_duration');
		
		
		$randomIdArr = explode(",",$request->input('random_id'));
	 
