	public function replayShareFileDoc(Request $request) {
		
		$user = Auth::user();
		$user_id = $user->id;
		$institute_id = $user->institute_id;
		$userTimeZone = !empty($user->time_zone) ? $user->time_zone : Config::get('app.timezone');
		
		$academic_session_id =  Session::get('aSessionId');		
	    $semester_id =  Session::get('semesterId'); 
		
		$locale = Session::get('locale');
		$group_id = $request->input('group_id');
		$groupchat_id = $request->input('groupchat_id');
		$gradesection_group_id = $request->input('gradesection_group_id');
		$b2c_group_id = $request->input('b2c_group_id');
		
		$recevier_id = $request->input('recevier_id');
		
		$date_time = $request->input('date_time');
		$currentDateTime = Carbon::now($userTimeZone)->format('Y-m-d H:i:s');
		$utcCurrentDateTime = Carbon::createFromFormat('d-M-Y h:i a',trim($date_time), $userTimeZone)->setTimezone('UTC')->format('Y-m-d H:i:s');
	
		
		$active_group_id = $request->input('active_group_id');
		$message = trim($request->input('txt_message'));
		$active_file = $request->input('active_file');
		$reply_message_id = $request->input('reply_message_id');
		$reply_share_message_id = $request->input('reply_share_message_id');
		$randomIdArr = explode(",",$request->input('random_id'));
		$track_duration = $request->input('track_duration');
	 
		$recevierIdArr = array_unique(explode(",",$recevier_id));
		$groupIdArr = array_unique(explode(",",$group_id));
		$share_fileArr = array();
		$dataArr = array();
		
		if ($request->hasfile('file')) {
			foreach($request->file('file') as $file) {
			 	$fileName = $file->getClientOriginalName();
				$extension = $file->getClientOriginalExtension();
				$file_mime_type = $file->getClientMimeType();
				$upload_path = public_path().'/uploads/chat_share_file/';
				if (!file_exists($upload_path)) {
					mkdir($upload_path, 0777, true);
				}
				
				if (strcmp($active_file, $fileName) == 0) {
					  $is_active_file = 1;
				}else {
					   $is_active_file = 0;
				}
				$file_name = uniqid().'_'.time().'.'.$extension;
				$file->move($upload_path, $file_name);
				$pdftoimg = "";
				if($extension=='pdf'){
				  $pdftoimg = Helper::pdftoImg($file_name);
				}
				$dataArr[] = array('file_name'=>$file_name,
									'file_mime_type'=>$file_mime_type,
									'file_type'=>2,
									'is_active_file'=>$is_active_file,
									'other_file'=>$pdftoimg,
									'created_date'=>$utcCurrentDateTime);
			}
		}
			$senderArr = array('sender_id' => $user_id ,
								'institute_id' => $institute_id,
								'academic_session_id' => $academic_session_id ,
								'semester_id' => $semester_id ,
								'msg' => $message,
								'is_reply' => 1,
								'file_type' => 3,
								'track_duration'=>!empty( $track_duration) ? $track_duration : '',
								'status' => 1,
								'created_at' => $utcCurrentDateTime,
							);
							if(!empty($reply_message_id)){
								$senderArr['reply_message_id']= $reply_message_id;
								if(!empty($reply_share_message_id)){
									$senderArr['reply_share_message_id'] = $reply_share_message_id;
								}
							}
		$groupMember="";
		if(!empty($gradesection_group_id) && empty($group_id) && empty($groupchat_id)){
						
				if(!empty($recevier_id)){
					$senderArr['group_id'] =$gradesection_group_id;
					$senderArr['is_name_header']= 1;
					$insert_Id = DB::table('chat_msg')->insertGetId($senderArr);
					if($insert_Id){
						foreach($recevierIdArr as $key=>$recevierIdArrVal){
							$chatMsgStatus = array(
								'receiver_id' => $recevierIdArrVal,
								'chat_msg_id' =>$insert_Id,
								'is_read' => 0,
								'status' => 0,
								'chat_msg_type' => 1,
								'created_at' => $utcCurrentDateTime,
							);
						   DB::table('chat_msg_status')->insert($chatMsgStatus);
						}
						if(!empty($dataArr)){
							foreach($dataArr as $key => $csm){
							  $dataArr[$key]['chat_id'] = $insert_Id;
							}
							
						 DB::table('chat_shared_file')->insert($dataArr);	
						}
					}
				}
		}
		else if(!empty($groupchat_id) && empty($group_id) && empty($gradesection_group_id)){
			$groupMember = DB::table('chat_group_member')->select('user_id','group_id')->where('chat_group_member.group_code', '=', $groupchat_id)->where('chat_group_member.user_id', '!=' ,$user_id)->get()->all();
			$senderArr['group_id'] = $groupchat_id;	
			$senderArr['is_name_header']= 1;
			$insert_Id = DB::table('chat_msg')->insertGetId($senderArr);
			$chatMsgStatus= array();
			if($insert_Id){
				foreach($groupMember as $key=>$group_memberVal){
					$chatMsgStatus[] = array(
									'receiver_id' =>$group_memberVal->user_id,
									'chat_msg_id' =>$insert_Id,
									'is_read' => 0,
									'status' => 0,
									'chat_msg_type' => 2,
									'created_at' => $utcCurrentDateTime,
								);
				}
				DB::table('chat_msg_status')->insert($chatMsgStatus);
				if(!empty($dataArr)){
					foreach($dataArr as $key => $csm){
					  $dataArr[$key]['chat_id'] = $insert_Id;
					}
					
				 DB::table('chat_shared_file')->insert($dataArr);	
				}
			}
		}
		
		elseif(!empty($b2c_group_id) && empty($group_id) && empty($gradesection_group_id) && empty($groupchat_id) ){
			
			if(!empty($recevier_id)){
				$senderArr['group_id']= $b2c_group_id;
				$insert_Id = DB::table('chat_msg')->insertGetId($senderArr);
				if($insert_Id){
						$chatMsgStatus = array(
							'receiver_id' => $recevier_id,
							'chat_msg_id' =>$insert_Id,
							'is_read' => 0,
							'chat_msg_type' => 3,
							'status' => 0,
							'created_at' => $utcCurrentDateTime,
						);
					DB::table('chat_msg_status')->insert($chatMsgStatus);
					if(!empty($imgArr)){
						foreach($imgArr as $key => $csm){
						  $imgArr[$key]['chat_id'] = $insert_Id;
						}
					 DB::table('chat_shared_file')->insert($imgArr);	
					}
					
				}
			}
		}
		
		else{
			if(!empty($recevier_id)){
				foreach($recevierIdArr as $key=>$recevierIdArrVal){
					$senderArr['group_id'] = $groupIdArr[$key];
					$insert_Id = DB::table('chat_msg')->insertGetId($senderArr);
					if($insert_Id){
							$chatMsgStatus = array(
								'receiver_id' => $recevierIdArrVal,
								'chat_msg_id' =>$insert_Id,
								'is_read' => 0,
								'status' => 0,
								'chat_msg_type' =>1,
								'created_at' => $utcCurrentDateTime,
							);
					   DB::table('chat_msg_status')->insert($chatMsgStatus);
					   
					   if(!empty($dataArr)){
							foreach($dataArr as $key => $csm){
							  $dataArr[$key]['chat_id'] = $insert_Id;
							}
							DB::table('chat_shared_file')->insert($dataArr);	
						}
					}
				}
			}
		}
		$totalMessage = array();
		$last_msg_info = DB::table('chat_msg as c')
							->select('c.id as chat_id', 'c.group_id', 'c.sender_id', 'c.msg',DB::raw("DATE_FORMAT(CONVERT_TZ(c.created_at, 'UTC', '{$userTimeZone}'),'%d-%m-%Y %h:%i %p') as date_time"), 'c.is_share_file', 'c.is_link','c.file_type','c.is_reply','c.reply_message_id','c.is_name_header','u.id','u.profile_pic','u.fullname as sender_name')
							->join('users', 'users.id', '=', 'c.sender_id')
							->where('c.group_id', '=', $active_group_id)
							->where('c.sender_id', '=', $user_id)
							->where('c.institute_id', '=', $institute_id)
							->where('c.academic_session_id', '=', $academic_session_id)
							->where('c.semester_id', '=', $semester_id)
							->orderBy('chat_id', 'DESC')
							->first();
							
		if (!empty($last_msg_info->profile_pic)) {
