	public function saveSendMessageReplay(Request $request) {
		$user = Auth::user();
		$user_id = $user->id;
		$institute_id = $user->institute_id;
		$userTimeZone = !empty($user->time_zone) ? $user->time_zone : Config::get('app.timezone');
		
		$academic_session_id =  Session::get('aSessionId');		
	    $semester_id =  Session::get('semesterId'); 
		
		$recevier_id = $request->input('recevier_id');
		$group_id = $request->input('group_id');
		$groupchat_id = $request->input('groupchat_id');
		$gradesection_group_id = $request->input('gradesection_group_id');
		$b2c_group_id = $request->input('b2c_group_id');
		$active_group_id = $request->input('active_group_id');

		
		$date_time = $request->input('date_time');
		//$msg_date = $request->input('msg_date');
		$msg_time = $request->input('msg_time');
		$message = $request->input('message');
		$update_message_id = $request->input('update_message_id');
		$reply_message_id = $request->input('reply_message_id');
		$reply_share_message_id = $request->input('reply_share_message_id');
		$track_duration = $request->input('track_duration');
		$recevierIdArr = array_unique(explode(",",$recevier_id));
		$groupIdArr = array_unique(explode(",",$group_id));
		$insert_Id="";
		$group_member="";
		$file_type = 0;
		
		$currentDateTime = Carbon::now($userTimeZone)->format('Y-m-d H:i:s');
		$utcCurrentDateTime = Carbon::createFromFormat('Y-m-d H:i:s',trim($currentDateTime), $userTimeZone)->setTimezone('UTC')->format('Y-m-d H:i:s');
		
		
		if (filter_var($message, FILTER_VALIDATE_URL)) { $file_type = 4; }
		
		if(!empty($gradesection_group_id) && empty($group_id) && empty($groupchat_id) && empty($b2c_group_id)){
			if(!empty($recevier_id)){
				$senderArr = array(
								'group_id' =>$gradesection_group_id,
								'institute_id' => $institute_id ,
								'academic_session_id' => $academic_session_id,
								'semester_id' => $semester_id,
								'sender_id' => $user_id ,
								'msg' => $message,
								'file_type' => $file_type,
								'track_duration' => !empty($track_duration)? $track_duration :'',
								'is_name_header' => 1,
								'status' => 1,
								'created_at' => date('Y-m-d H:i:s'),
							);
				if(!empty($reply_message_id)){
					$senderArr['is_reply']=1;
					$senderArr['reply_message_id']= $reply_message_id;
					if(!empty($reply_share_message_id)){
						$senderArr['reply_share_message_id'] = $reply_share_message_id;
					}
				}
				$insert_Id = DB::table('chat_msg')->insertGetId($senderArr);	
					if($insert_Id){
					foreach($recevierIdArr as $key=>$recevierId){
						$chatMsgStatus[] = array(
							'receiver_id' => $recevierId,
							'chat_msg_id' =>$insert_Id,
							'is_read' => 0,
							'status' => 0,
							'created_at' => date('Y-m-d H:i:s'),
						);
					}
				}
				DB::table('chat_msg_status')->insert($chatMsgStatus);
			}
		}
		else if(!empty($groupchat_id) && empty($group_id) && empty($gradesection_group_id) && empty($b2c_group_id)){
					
				$group_member = DB::table('chat_group_member')->select('user_id','group_id')->where('chat_group_member.group_code', '=', $groupchat_id)->where('chat_group_member.user_id', '!=' ,$user_id)->get()->all();
				$senderArr = array(
								'group_id' => $groupchat_id,
								'institute_id' => $institute_id ,
								'academic_session_id' => $academic_session_id,
								'semester_id' => $semester_id,
								'sender_id' => $user_id ,
								'msg' => $message,
								'file_type' => $file_type,
								'track_duration' => !empty($track_duration)? $track_duration :'',
								'status' => 1,
								'is_name_header' => 1,
								'created_at' => date('Y-m-d H:i:s'),
							);
						if(!empty($reply_message_id)){
							$senderArr['is_reply']=1;
							$senderArr['reply_message_id']= $reply_message_id;
							if(!empty($reply_share_message_id)){
								$senderArr['reply_share_message_id'] = $reply_share_message_id;
							}
						}	
					$insert_Id = DB::table('chat_msg')->insertGetId($senderArr);
					$chatMsgStatus= array();
					foreach($group_member as $key=>$group_memberVal){
						$chatMsgStatus[] = array(
											'receiver_id' =>$group_memberVal->user_id,
											'chat_msg_id' =>$insert_Id,
											'is_read' => 0,
