	public function serachUserMediaTxt(Request $request) {
        $user = Auth::user();
		$user_id = $user->id;
		$institute_id = $user->institute_id;
		$userTimeZone = !empty($user->time_zone) ? $user->time_zone : Config::get('app.timezone');
		
		
		
        $serach_txt = $request->serach_user_media_txt;
		
		$my_schools = DB::table('member_section')
					->select(DB::raw('group_concat(member_school.school_id) as school_id'),DB::raw('group_concat(member_section.grade_id) as grade_id'),DB::raw('group_concat(member_section.section_id) as section_id'))
					->join('member_school', 'member_section.user_id', '=', 'member_school.user_id') 
					->where('member_section.user_id', '=', $user_id)
					->where('member_section.status', '=', 1)
					->groupBy('member_section.user_id')
					->get()->first();
					
		$schoolArr = array();
		$gradeArr = array();
		$sectionArr = array();
	
		if(!empty($my_schools)){
			  $schoolArr = array_unique(explode(',',$my_schools->school_id));
			  $gradeArr = array_unique(explode(',',$my_schools->grade_id));
			  $sectionArr = array_unique(explode(',',$my_schools->section_id));
			
		}
		
		$school_students = DB::table('users')
						->select('users.id as student_id',DB::raw('CONCAT(users.first_name, " ",users.last_name) AS student_name'),'member_grade.grade_name','member_section.section_name','member_school.school_id','member_section.grade_id','member_section.section_id')
						->join('member_school', 'member_school.user_id', '=', 'users.id')
						->join('member_grade', 'member_grade.user_id', '=', 'users.id')
						->join('member_section', 'member_section.user_id', '=', 'users.id')
						->where('users.role_id','=',3)
						->whereIn('member_school.school_id',$schoolArr)
						->whereIn('member_section.grade_id',$gradeArr)
						->whereIn('member_section.section_id',$sectionArr)
						->where('member_section.status','=',1)
						->Where(function ($query) use ($serach_txt) {
								$query->Where('users.first_name', 'like', '%' . $serach_txt . '%');
								$query->orWhere('users.last_name', 'like', '%' . $serach_txt . '%');
						})
						->groupBy('users.id')
						->orderBy('users.first_name','ASC')
						->get()->all();
						
		$return_view= '<ul class="collapsible main_tabigni"  data-collapsible="accordion">';	
		$allowedImg = array('gif', 'png', 'jpg','jpeg');		
		
		$student_imgCls="'student_imgCls'";
		$student_mediaCls="'student_mediaCls'";
		$student_docCls="'student_docCls'";
		$student_forwarlinkCls="'student_forwarlinkCls'";
		
