			foreach($school_students as $school_studentsVal){
				 $gradesection = '('.$school_studentsVal->grade_name.')'.$school_studentsVal->section_name;
				 //$mediaDocLinks = Helper::getMediaDocLinks($school_studentsVal->student_id);
