                                  <i class="material-icons right less" style="display: none">expand_less</i>
                                  <span class="nim_main"><i class="material-icons dp48">grade</i>'.ucfirst($school_studentsVal->student_name).' '.$gradesection.'</span>
                                </div>
                                <div class="collapsible-body" style="display: none;">
                                  <div class="mid_school"> 
                                      <div class="row">
                                        <div class="col s12">
                                          <ul class="tabs">
                                            <li class="tab col s3"><a class="active" href="#test1_'.$school_studentsVal->student_id.'">Images</a></li>
                                            <li class="tab col s3"><a href="#test2_'.$school_studentsVal->student_id.'">Media</a></li>
                                            <li class="tab col s3"><a href="#test3_'.$school_studentsVal->student_id.'">Docs</a></li>
											<li class="tab col s3"><a href="#test4_'.$school_studentsVal->student_id.'">Links</a></li>
                                          </ul>
                                        </div>
