										 			$html_one .='<div class="bookBottom">
														<a id="downloadImageID_'.$school_studentsVal->student_id.'" class=""  href="javascript:void(0)" onclick="download_media_doc('.$school_studentsVal->student_id.','.$student_imgCls.')" style="display:none">'.__('messages.download').' Select Media</a>
													    <a id="forwordImageID_'.$school_studentsVal->student_id.'" onclick="forword_media('.$school_studentsVal->student_id.','.$student_imgCls.')" class="" style="display:none">'.__('messages.forward').'</a>
