																}
															$html_two .= $strContent.'</span>'.$mediaDocVal->file_name.'<a href="javascript:void(0)" onclick="single_forward('.$school_studentsVal->student_id.','.$mediaDocVal->id.','.$student_mediaCls.',1)" class="forwardIconCls"><img src="'.url('/').'/resources/assets/images/forward_icon.png"></a><a href="'.url('/').'/multiple-download-media/'.$mediaDocVal->id.'" class="downloadIconCls" download><img src="'.url('/').'/resources/assets/images/download_icon.png"></a><span class="forwardDateTimeCls">'.$dateTime.'</span></span>'; 
														}
