    public function readGroupMessage(Request $request) {
        $user_id = Auth::user()->id;
		
		
        $group_id = $request->group_id;

        $result = DB::table('chat_msg_status')
                ->select(DB::raw('group_concat(chat_msg.id) as message_id'))
                ->join('chat_msg', 'chat_msg.id', '=', 'chat_msg_status.chat_msg_id')
                ->where('receiver_id', '=', $user_id)
                ->where('chat_msg_status.status', '=', 0)
                ->where('chat_msg.group_id', '=', base64_encode($group_id))
                ->get()->first();
      if (!empty($result)) {
            $message_id = explode(',', $result->message_id);
            DB::table('chat_msg_status')
                    ->whereIn('chat_msg_status.chat_msg_id', $message_id)
                     ->where('receiver_id', '=', $user_id)
                    ->update(['is_read' => 1, 'status' => 1, 'updated_at' => date('Y-m-d H:i:s')]);
            
             $groupMessageCount = DB::table('chat_msg_status')
                                ->join('chat_msg', 'chat_msg.id', '=', 'chat_msg_status.chat_msg_id')
                                ->where('chat_msg.group_id', '=',base64_encode($group_id))
                                ->where('receiver_id','=',$user_id)
                                ->where('chat_msg_status.is_read','=',0)
                                ->count();
            
            return response()->json(['status' => true,'groupMessageCount'=>$groupMessageCount,'group_id'=>$group_id]);
        } else {
            return response()->json(['status' => false,'groupMessageCount'=>0]);
        }
    }
	
