							->where('c.group_id', '=', $active_group_id)
							->where('c.sender_id', '=', $user_id)
							->where('c.institute_id', '=', $institute_id)
							->where('c.academic_session_id', '=', $academic_session_id)
							->where('c.semester_id', '=', $semester_id)
							->orderBy('chat_id', 'DESC')
							->first();
							
			if (!empty($last_msg_info->profile_pic)) {
				$path = parse_url($last_msg_info->profile_pic);
				if(isset($path['scheme']) == 'https' || isset($path['scheme']) == 'http'){
					$url = $last_msg_info->profile_pic;
				}else{
					$url = url('/') . '/public/uploads/profile_img/' . $last_msg_info->profile_pic;	
				}
			} else {
				$url = url('/') . '/resources/assets/images/teacher_icon.png';
			}
			
			$last_message = !empty($last_msg_info->msg)? $last_msg_info->msg :'';	
			$message_date_time = Helper::getDatetime($last_msg_info->date_time);
			$chat_id = !empty($last_msg_info->chat_id)? $last_msg_info->chat_id :'';
			
			$chat_message='<div class="message" id="chatMessageDiv_'.$chat_id.'">
								<img src="'.$url.'" alt="">
								<div class="bubble">
									'.$sendlink.'	
									<div class="corner"></div>
									<span>'.$message_date_time.'</span>
								</div>
							</div>';
					
			$total_message = Helper::getMessageCount($recevier_id); 
			$total_group_message = Helper::getMessageCountByUser($recevier_id,$user_id); 
			$totalMessage[] = array('total_message'=>$total_message,
									'receiver_id'=>$recevier_id,
									'total_group_message'=>$total_group_message,
									'chat_message'=>$chat_message,
									'last_message'=>$last_message,
									'message_time'=>'',
								   );
			$msgsend =  array('message' =>'',
							  'totalMessage'=>$totalMessage,
							  'gid'=>$active_group_id,
							  'chatboxmsgid'=>base64_decode($active_group_id),
							  'chat_id'=>$chat_id,
							  'sender_id'=>$user_id,
							  'message_type'=>'');                              
			event(new ChatMessage($msgsend));
			return response()->json(['status' => true,'start_url'=>$start_url,'sendlink'=>$sendlink]);
		}
		
	}

	public function removeMeetInClassroom() {
	
        $user_id = Auth::user()->id;
        $messageID = DB::table('chat_msg')
                ->select(DB::raw('group_concat(chat_msg.id) as message_id'))
                ->where('chat_msg.sender_id', '=', Auth::user()->id)
                ->where('chat_msg.is_meet_in_classroom', '=', 1)
                ->whereRaw('chat_msg.created_at <= DATE_SUB(NOW(),INTERVAL 40 MINUTE)')
                ->get()->first();
        if (!empty($messageID->message_id)) {
            $message_id = explode(',', $messageID->message_id);
            $totalmessage = DB::table('chat_msg')
                            ->where('chat_msg.sender_id', '=', Auth::user()->id)
                            ->whereIn('chat_msg.id', $message_id)
                            ->delete();
                            DB::table('chat_msg_status')
                            ->whereIn('chat_msg_status.chat_msg_id', $message_id)
                            ->delete();
            return response()->json(['status' => true,'message' => 'remove meet in classroom']);
        } else {
            return response()->json(['status' => false,'message' => 'no data histroy meet in classroom']);
        }
    }

    public function getmessageCounter() {
        $user_id = Auth::user()->id;
        $totalmessage = DB::table('chat_msg_status')
                ->where('receiver_id', '=', $user_id)
                ->where('chat_msg_status.is_read', '=', 0)
                ->where('chat_msg_status.status', '=', 0)
                ->count();
        return response()->json(['status' => true, 'totalmessage' => $totalmessage,]);
    }
		
    public function serachTxt(Request $request) {
        $user = Auth::user();
