					})
					->select('chat_group.id', 'chat_group.group_name', 'chat_group.group_image', 'chat_group.group_id', DB::raw('(SELECT SUM(chat_msg_status.is_read = 0 AND chat_msg_status.status = 0) FROM chat_msg JOIN chat_msg_status ON chat_msg_status.chat_msg_id = chat_msg.id WHERE chat_msg.group_id = chat_group.group_id AND chat_msg_status.receiver_id = "' . $user_id . '") AS unread_count'))
					->where(['chat_group.institute_id' => $institute_id, 'chat_group.status' => 1])
					->where(function ($query) use ($serach_txt) {
						$query->orWhere('group_name', 'like', '%' . $serach_txt . '%');
					})
