	public function downloadMultipleMediaByID($id="",Request $request){
		$zip = new ZipArchive;	
		$ids = explode(',',$id);
		$share_file = DB::table('chat_shared_file')
					->whereIn('id',$ids)
					->pluck('file_name')->toArray();
		$filename ="";
		
		if(!empty($share_file)){
			if(count($share_file)>1){
				$filename = time().".zip";
				$zip->open($filename, ZipArchive::CREATE);
				foreach($share_file as $share_fileVal){
					$path = public_path().'/uploads/chat_share_file/'.$share_fileVal;
					if(file_exists($path)){
						$zip->addFromString(basename($path), file_get_contents($path));  
					}
				}
				$zip->close();	
			}else{
				foreach($share_file as $share_fileVal){
					$filename = public_path('uploads/chat_share_file/'.$share_fileVal);
				}
			}
		}
	    return response()->download($filename);
	}
	
	public function download($id = '' ){
        $share_file = DB::table('chat_msg')->where(['id'=>$id,'is_share_file'=>1])->first();
        $file_path = public_path('uploads/chat_share_file/'.$share_file->msg);
        return response()->download($file_path);
    }
	
