		$message_forward_id = $request->input('forward_mdi_message_id');
		$forward_mdi_message = $request->input('forward_mdi_message');
		$forward_type = $request->input('forward_mdi_type');
		
		$now = Carbon::now();
		$userTimeZone = $now->timezone->getName();
		
		$currentDateTime = Carbon::now($userTimeZone)->format('Y-m-d H:i:s');
		$utcCurrentDateTime = Carbon::createFromFormat('Y-m-d H:i:s',$currentDateTime, $userTimeZone)->setTimezone('UTC')->format('Y-m-d H:i:s');
		
		
		$file_type="";
		if($forward_type=='all' || $forward_type==1){
			$file_type=1;
		}
		elseif($forward_type==2){
				$file_type=2;
		}
		elseif($forward_type==3){
			$file_type=3;
		}
		 
		$groupIdArr = explode(",",$group_id);
		$messageForwardIdArr = explode(",",$message_forward_id);
		$messageForwardArr = explode(",",$forward_mdi_message);
		
		
		$sharemessageArr = array();	
	  	$chatgroupmessageArr = array();
	  	$sharegroupmessageArr = array();
		$groupsUserArr = array();
		$totalMessage = array();
		if($forward_type ==4){
				if(!empty($cgroup)){
					$forward_type='cgroup';
					$cgroupArr = array();
					$cgroupcounter=1;
					foreach($cgroup as $key=>$cgroupVal){
							if($cgroupcounter == 1){
								$cgroupArr['cgroup_code'] = $cgroupVal;  
								$cgroupArr['cgroup_id'] = $key; 
								$cgroupcounter++;						
							}
						
						
						  $chatmessageArr = array();	
						  $groupMember = DB::table('chat_group_member')
										->select('user_id', 'chat_group_member.group_id')
										->Join('chat_group', 'chat_group_member.group_id','=','chat_group.id')
										->where('chat_group.group_id','=',$cgroupVal)
										->where('chat_group_member.user_id', '!=' ,$user_id)->get();
							
										$senderArr = array(
											'group_id' =>$cgroupVal,
											'institute_id' => $institute_id ,
											'academic_session_id' => $academic_session_id ,
											'semester_id' => $semester_id ,
											'is_forward' => 1,
											'sender_id' => $user_id ,
											'file_type' =>4,
											'is_name_header' => 1,
											'status' => 1,
											'created_at' => $utcCurrentDateTime,
										);
										foreach($messageForwardArr as $key1=>$messageVal){
											$senderArr['msg'] = $messageVal;
											$insert_Id = DB::table('chat_msg')->insertGetId($senderArr);
											$chatMsgStatus = array();
											if($insert_Id){
												foreach($groupMember as $key=>$recevierIdArrVal){
													$chatMsgStatus[] = array(
														'receiver_id' => $recevierIdArrVal->user_id,
														'chat_msg_id' =>$insert_Id,
														'is_read' => 0,
														'status' => 0,
														'created_at' =>$utcCurrentDateTime,
													);
												}
												DB::table('chat_msg_status')->insert($chatMsgStatus);
