	public function removeChatMessage(Request $request){
		
		$user_id = Auth::user()->id;
		$student_id = $request->student_id;
		$active_group_id = $request->active_group_id;
		$chat_id = $request->chat_id;
		$share_file_id = $request->share_file_id;
		$group_id = $request->group_id;
		$groupchat_id = $request->groupchat_id;
		$gradesection_group_id = $request->gradesection_group_id;
		$b2c_group_id = $request->b2c_group_id;
		$recevier_id = $request->recevier_id;
		
		$res ="";
		$remove_message_id="";
		
		$messagerReceiverId =  DB::table('chat_msg_status')
							->select(DB::raw("GROUP_CONCAT(chat_msg_status.receiver_id) as receiver_id"))
							->join('chat_msg','chat_msg_status.chat_msg_id','=','chat_msg.id')
							->where('chat_msg.id', '=',$chat_id)
							->groupBy('chat_msg.group_id')
							->first();
	
		if(!empty($share_file_id)){
			$remove_message_id= "";
			$res =  DB::table('chat_msg')->where('id', '=',$chat_id)->delete();
			if($res){
				$res =  DB::table('chat_shared_file')->where(['id'=>$share_file_id,'chat_id'=>$chat_id])->delete();
			}
			$remove_message_id= $chat_id.'_'.$share_file_id;
		}else{
			$res =  DB::table('chat_msg')->where('id', '=',$chat_id)->delete();
			if($res){
				$remove_message_id= $chat_id;
				$result = DB::table('chat_shared_file')->where(['chat_id'=>$chat_id])->get()->first();
				if($result){
					$res =  DB::table('chat_shared_file')->where(['chat_id'=>$chat_id])->delete();
				}	
			}
		} 						
	
		if(!empty($res)){
			$totalMessage = array();
			
			if(!empty($gradesection_group_id) && empty($groupchat_id) && empty($group_id)){
				
				$memberArr = explode(",",$messagerReceiverId->receiver_id);
				foreach($memberArr as $key=>$memberID){
				
					$total_message = Helper::getMessageCount($memberID); 
					$totalMessage[] = array(
											'total_message'=>$total_message,
											'receiver_id'=>$memberID
										   ); 
				}
				$msgsend =  array('totalMessage'=>$totalMessage,
								  'sender_id'=>$user_id,
								  'gradesection_id'=>$active_group_id,
								  'chatboxmsgid'=>base64_decode($active_group_id),
								  'gid'=>$active_group_id,
								  'update_message_id'=>'',
								  'removeMsgId'=>$remove_message_id,
								  'removeBulkMsgId'=>'',
								  'message_type'=>'gradesectionchat'); 
				
			}
			else if(!empty($groupchat_id) && empty($gradesection_group_id) && empty($group_id)){
				$memberArr = explode(",",$messagerReceiverId->receiver_id);
				foreach($memberArr as $key=>$memberID){
				
					$total_message = Helper::getMessageCount($memberID); 
					$totalMessage[] = array(
											'total_message'=>$total_message,
											'receiver_id'=>$memberID
										   ); 
				}
				$msgsend =  array('totalMessage'=>$totalMessage,
								  'sender_id'=>$user_id,
								  'cgroupcode'=>$active_group_id,
								  'chatboxmsgid'=>base64_decode($active_group_id),
								  'gid'=>$active_group_id,
								  'update_message_id'=>'',
								  'removeMsgId'=>$remove_message_id,
								  'removeBulkMsgId'=>'',
								  'message_type'=>'groupschat'); 
				
			
			}
			else if(!empty($b2c_group_id)&& empty($gradesection_group_id) && empty($group_id)){
				$total_message = Helper::getMessageCount($memberID); 
				
				$msgsend =  array('total_message'=>$total_message,
								  'receiver_id'=>$messagerReceiverId->receiver_id,
								  'sender_id'=>$user_id,
								  'chatboxmsgid'=>base64_decode($active_group_id),
								  'gid'=>$active_group_id,
								  'update_message_id'=>'',
								  'removeMsgId'=>$remove_message_id,
								  'removeBulkMsgId'=>'',
								  'message_type'=>'b2c'); 
			}
			else{
				
				$total_message = Helper::getMessageCount($memberID); 
				$totalMessage[] = array(
										'total_message'=>$total_message,
										'receiver_id'=>$messagerReceiverId->receiver_id
									   ); 
				$msgsend =  array('totalMessage'=>$totalMessage,
								  'sender_id'=>$user_id,
								  'chatboxmsgid'=>base64_decode($active_group_id),
								  'gid'=>$active_group_id,
								  'update_message_id'=>'',
								  'removeMsgId'=>$remove_message_id,
								  'removeBulkMsgId'=>'',
								  'message_type'=>''); 
				
				
			}
			event(new ChatMessage($msgsend));
			return response()->json(['status' => true,'chat_id' =>$remove_message_id,'message'=>'message deleted succesfullly']);
		}else{
		   return response()->json(['status' => false,'message'=>'message not delete']);
		}
	}
	
	public function removeBulkChatMessage(Request $request){
		$user_id = Auth::user()->id;
		$chat_id = $request->chat_id;
		$group_id = $request->group_id;
		$groupchat_id = $request->groupchat_id;
		$gradesection_group_id = $request->gradesection_group_id;
		$b2c_group_id = $request->b2c_group_id;
		$active_group_id = $request->active_group_id;
		$recevier_id = $request->recevier_id;
		
		$res ="";
		$query = DB::table('chat_shared_file');
		
		foreach ($chat_id as $idsVal) {
			$file_ids = explode('_',$idsVal);
			if(!empty($file_ids[1])){
				$res =  DB::table('chat_msg')->where('id', '=',$file_ids[0])->delete();
				if($res){
					$result = DB::table('chat_shared_file')->where(['chat_id'=>$file_ids[0]])->get()->first();
					if($result){
						$res =  DB::table('chat_shared_file')->where(['chat_id'=>$file_ids[0],'id'=>$file_ids[1]])->delete();
					}	
				}
			}else{
				$res =  DB::table('chat_msg')->where('id', '=',$file_ids[0])->delete();
				if($res){
					$result = DB::table('chat_shared_file')->where(['chat_id'=>$file_ids[0]])->get()->first();
					if($result){
						DB::table('chat_shared_file')->where(['chat_id'=>$file_ids[0]])->delete();
					}	
				}
			}
		}
		
		
		if(!empty($res)){
			$totalMessage = array();
			if(!empty($gradesection_group_id) && empty($groupchat_id) && empty($group_id)){
				$groupMember = !empty($recevier_id) ? $recevier_id :''; 
				$memberArr = explode(",",$groupMember);
				foreach($memberArr as $key=>$memberID){
					$total_message = Helper::getMessageCount($memberID); 
					$total_group_message = Helper::getGroupMessageCount($memberID,$active_group_id);
					$totalMessage[] = array(
											'total_message'=>$total_message,
											'total_group_message'=>$total_group_message,
											'receiver_id'=>$memberID
										   ); 
				}
				$msgsend =  array('totalMessage'=>$totalMessage,
				'sender_id'=>$user_id,
				'gid'=>$active_group_id,
				'chatboxmsgid'=>base64_decode($active_group_id),
				'gradesection_id'=>$gradesection_group_id,
				'update_message_id'=>'',
				'removeMsgId'=>'',
				'removeBulkMsgId'=>$chat_id,
				'message_type'=>'gradesectionchat'); 
			}
			else if(!empty($groupchat_id) && empty($gradesection_group_id) && empty($group_id)){
				$groupMember = DB::table('chat_group_member')->select('user_id','group_id')->where('chat_group_member.group_code', '=', $groupchat_id)->where('chat_group_member.user_id', '!=' ,$user_id)->get()->all();
				foreach($groupMember as $member){
					$total_message = Helper::getMessageCount($member->user_id); 
					$total_group_message = Helper::getGroupMessageCount($member->user_id,$active_group_id);
					$totalMessage[] = array(
											'total_message'=>$total_message,
											'total_group_message'=>$total_group_message,
											'receiver_id'=>$member->user_id
										   ); 
				}
				$msgsend =  array('totalMessage'=>$totalMessage,
									'sender_id'=>$user_id,
									'cgroupcode'=>$groupchat_id,
									'gid'=>$active_group_id,
								    'chatboxmsgid'=>base64_decode($active_group_id),
									'update_message_id'=>'',
									'removeMsgId'=>'',
									'removeBulkMsgId'=>$chat_id,
									'message_type'=>'groupschat'); 
			}
			else if(!empty($b2c_group_id)&& empty($gradesection_group_id) && empty($group_id)){
				$total_message = Helper::getMessageCount($memberID); 
				
				$msgsend =  array('total_message'=>$total_message,
								  'receiver_id'=>$messagerReceiverId->receiver_id,
								  'sender_id'=>$user_id,
								  'chatboxmsgid'=>base64_decode($active_group_id),
								  'gid'=>$active_group_id,
								  'update_message_id'=>'',
								  'removeMsgId'=>'',
								  'removeBulkMsgId'=>$chat_id,
								  'message_type'=>'b2c'); 
			}
			else{
			$memberID	 = !empty($recevier_id) ? $recevier_id :''; 
			$total_message = Helper::getMessageCount($memberID); 
			$total_group_message = Helper::getGroupMessageCount($memberID,$active_group_id);
			$totalMessage[] = array(
								'total_message'=>$total_message,
								'total_group_message'=>$total_group_message,
								'receiver_id'=>$memberID
							   ); 
		  $msgsend =  array('totalMessage'=>$totalMessage,
							'sender_id'=>$user_id,
							'group_id'=>$active_group_id,
							'gid'=>$active_group_id,
							'chatboxmsgid'=>base64_decode($active_group_id),
							'update_message_id'=>'',
							'removeMsgId'=>'',
							'removeBulkMsgId'=>$chat_id,
							'message_type'=>''); 
		}	
			event(new ChatMessage($msgsend));
			return response()->json(['status'=> true,'chat_id' =>$chat_id,'message'=>'message deleted succesfullly']);
		}else{
		   return response()->json(['status'=> false,'message'=>'message not delete']);
		}
	}
	
	public function getStudentListPageHtml(Request $request){
		$user = Auth::user();
        $user_id = $user->id;
        $institute_id = $user->institute_id;
		$academic_session_id =  Session::get('aSessionId');		
	    $semester_id =  Session::get('semesterId');
		
		$request_type =  $request->type; 
		$search_txt =  $request->search_txt; 
		
		 $tutorGradeSection = DB::table('member_section')
							->select('user_id','grades.school_id','grade_id','section_id','grade','section_name')
							->join('grades', function ($join) use ($academic_session_id, $semester_id) {
								$join->on('member_section.grade_id', '=', 'grades.id')
									->where('member_section.academic_session_id', '=', $academic_session_id)
									->where('member_section.semester_id', '=', $semester_id)
									->where('member_section.status', '=', 1);
							})
							//->join('grades','member_section.grade_id','=','grades.id')
							->where(['member_section.user_id'=>$user_id,'grades.institute_id'=>$institute_id])
							->orderBy('grades.grade')->get()->all();
		$mainGroupArr = array(); 
		$studentGroupArr =array(); 
		
		if(!empty($tutorGradeSection)){
			foreach($tutorGradeSection as $key=>$tutorGradeSectionVal){
				$main_group_id =  base64_encode($tutorGradeSectionVal->school_id.'-'.$tutorGradeSectionVal->grade_id.'-'.$tutorGradeSectionVal->section_id.'-'.$tutorGradeSectionVal->user_id);
				
				$last_msg_info = DB::table('chat_msg as c')
								->select('c.id as chat_id')
								->leftJoin('chat_shared_file','chat_shared_file.chat_id', '=', 'c.id')
								->where('c.group_id', '=', $main_group_id)
								->orderBy('created_at', 'DESC')
								->first();
				
				$mainGroupArr[] = array('main_group_id'=>$main_group_id,
										'chat_id'=>!empty($last_msg_info->chat_id) ? $last_msg_info->chat_id:'',
										'group_id'=>'',
										'school_id'=>$tutorGradeSectionVal->school_id,
										'grade_id'=>$tutorGradeSectionVal->grade_id,
										'section_id'=>$tutorGradeSectionVal->section_id,
										'user_id'=>$tutorGradeSectionVal->user_id,
										'group_name' => $tutorGradeSectionVal->grade.' ('.$tutorGradeSectionVal->section_name.')',
										'group_image' => url('/').'/public/uploads/icon/icon_1644316802.png'
										); 
				$students = DB::table('users')
							->select('users.id as student_id', 'users.fullname', 'users.profile_pic', 'users.is_login')
							->join('member_grade', function ($join) use ($academic_session_id, $semester_id, $tutorGradeSectionVal) {
								$join->on('member_grade.user_id', '=', 'users.id')
									->where('member_grade.academic_session_id', '=', $academic_session_id)
									->where('member_grade.semester_id', '=', $semester_id)
									->where('member_grade.status', '=', 1)
									->where('member_grade.grade_id', '=', $tutorGradeSectionVal->grade_id);
							})
							->join('member_section', function ($join) use ($academic_session_id, $semester_id, $tutorGradeSectionVal) {
								$join->on('member_section.user_id', '=', 'users.id')
									->where('member_section.academic_session_id', '=', $academic_session_id)
									->where('member_section.semester_id', '=', $semester_id)
									->where('member_section.status', '=', 1)
									->where('member_section.section_id', '=', $tutorGradeSectionVal->section_id);
							})
							->where('users.institute_id', '=', $institute_id)
							->where('users.role_id', '=', 3)
							->where(function ($query) use ($search_txt) {
								if (!empty($search_txt)) {
									$query->where('users.fullname', 'like', '%' . $search_txt . '%')
										->orWhere('users.first_name', 'like', '%' . $search_txt . '%');
								}
							})
							->orderBy('users.first_name', 'ASC')
							->get();

// The query is now optimized and ready to use the results.

				if(!empty(!empty($students))){
					foreach($students as $key=>$studentsVal){
						
						if (!empty($studentsVal->profile_pic)) {
							$path = parse_url($studentsVal->profile_pic);
							if(isset($path['scheme']) == 'https' || isset($path['scheme']) == 'http'){
							$group_image = $studentsVal->profile_pic;
							}else{
								$group_image = url('/').'/public/uploads/profile_img/'.$studentsVal->profile_pic;	
							}
						} else {
							$group_image = url('/').'/resources/assets/images/student_icon.png';
						}
						$groupID = base64_encode($tutorGradeSectionVal->school_id.'-'.$tutorGradeSectionVal->grade_id.'-'.$tutorGradeSectionVal->section_id.'-'.$studentsVal->student_id.'-'.$user_id);
						$last_msg_info = DB::table('chat_msg as c')
							->select('c.id as chat_id')
							->leftJoin('chat_shared_file','chat_shared_file.chat_id', '=', 'c.id')
							->where('c.group_id', '=', $groupID)
							->orderBy('created_at', 'DESC')
							->first();
						
						
						$mainGroupArr[] = array('main_group_id'=>'',
												'group_id'=>$groupID,
												'chat_id'=>!empty($last_msg_info->chat_id) ? $last_msg_info->chat_id:'',
												'school_id'=>$tutorGradeSectionVal->school_id,
												'grade_id'=>$tutorGradeSectionVal->grade_id,
												'section_id'=>$tutorGradeSectionVal->section_id,
												'user_id'=>$studentsVal->student_id,
												'group_name' =>$studentsVal->fullname.'- '.$tutorGradeSectionVal->section_name.'('.$tutorGradeSectionVal->grade.')',
												'group_image' =>$group_image,
												'is_login' =>$studentsVal->is_login
												); 
						
					}
				}
				
			}
		}
		$studentData = collect($mainGroupArr)->sortByDesc('chat_id')->values();
		$data['mainGroupArr'] = $studentData;
		$data['request_type'] = $request_type;
		if($request_type=='chatmessage_forward'){
			$returnHTML = view('tutor/_chatmessage_forward_student_list')->with($data)->render();	
		}else{
			$returnHTML = view('tutor/_forwad_media_student_list')->with($data)->render();	
		} 
	    return response()->json(['status' => true,'returnHTML'=>$returnHTML]);
        die;
		
		
	}
	
