	public function getChatUserList(){
		
        $user_id = Auth::user()->id;
		$gradeSectionArr= "";
		
		$schoolIDArr = member_school::where('user_id',$user_id)->pluck('school_id')->toArray();
		
		$tutorSchoolGrades =  DB::table('member_grade')
						->select('grades.school_id','member_grade.grade_id','grades.grade','member_section.section_id','member_section.section_name')
						//->join('member_section','member_section.user_id','=','member_grade.user_id')
						->join("member_section",function($join){
								$join->on("member_section.user_id","=","member_grade.user_id")
								->on("member_section.grade_id","=","member_grade.grade_id");
						})
						->join('grades','member_grade.grade_id','=','grades.id')
						->whereIn('grades.school_id',$schoolIDArr)
						->where(['member_section.user_id'=>$user_id])
						->orderBy('member_grade.grade_name') 
						->get()->all(); 
				$schoollists = array();		
						
				if(!empty($tutorSchoolGrades)){
		
					foreach ($tutorSchoolGrades as $key => $school_grade) {
						$studentArr= array();
						$school_students = DB::table('users')
								->select('users.id as student_id','users.first_name','users.last_name','users.fullname','users.profile_pic','users.is_login')
								->join('member_section', 'member_section.user_id', '=', 'users.id')
								->where('users.role_id','=',3)
								->where('member_section.grade_id','=',$school_grade->grade_id)
								->where('member_section.section_id','=',$school_grade->section_id)
								->where('member_section.status','=',1)
								//->limit(5)
								->orderBy('users.first_name', 'ASC')
								->get()->all();
								
						$students= array();		
						if(!empty($school_students)){
							foreach($school_students as $key=>$studentsVal){
								
								$group_id = !empty($studentsVal->student_id) ? base64_encode($school_grade->school_id.''.$school_grade->grade_id.''.$school_grade->section_id.''.$studentsVal->student_id.''.$user_id) : '';
								$parent_group = !empty($school_grade->section_id) ? base64_encode($school_grade->school_id.''.$school_grade->grade_id.''.$school_grade->section_id) : '';
								
								$checkchatgroup = DB::table('chat_group')->select('id')->where('group_id', '=', $group_id)->get()->first();
								
								if($checkchatgroup){
									DB::table('chat_group')->insert(['group_id' => $group_id,'parent_group' => $parent_group,'group_image' => null,'chat_type' => 1,'status' => 1,'created_at' => date('Y-m-d H:i:s')]);
								}
								
								$last_msg_info = DB::table('chat_msg as c')
								->select('c.id as chat_id', 'c.group_id', 'c.sender_id', 'c.msg', 'c.date', 'c.time','c.is_share_file','c.is_link')
								->where('c.group_id', '=', $group_id)
								->orderBy('created_at', 'DESC')
								->first();
								
								$students[] = array(
									'student_id'=>$studentsVal->student_id,
									'first_name'=>$studentsVal->first_name,
									'last_name'=>$studentsVal->last_name,
									'fullname'=>$studentsVal->fullname,
									'is_login'=>$studentsVal->is_login,
									'profile_pic'=>$studentsVal->profile_pic,
									'group_id'=>$group_id,
									'chat_id'=>!empty($last_msg_info->chat_id) ? $last_msg_info->chat_id :'',
								);
							}
							
						}
						$schoollists[]= array(
									'school_id'=>$school_grade->school_id,
									'grade_id'=>$school_grade->grade_id,
									'grade_name'=>$school_grade->grade,
									'section_id'=>$school_grade->section_id,
									'section_name'=>$school_grade->section_name,
									'tutor_id'=>$user_id,
									'grade_section_group_id'=> base64_encode($school_grade->school_id.''.$school_grade->grade_id.''.$school_grade->section_id.''.$user_id),
									'students'=>$students,
								);
					 	
												
					}
				}				
						
		$data['tutor_id'] = $user_id;
		$data['schoollists'] = $schoollists;
		$returnHTML = view('tutor/_student_list_left_side')->with($data)->render();
        return response()->json(['status' => true,'returnHTML'=>$returnHTML]);
		
	}
		
	public function downloadBulkFilesByID($id="",Request $request){
		$zip = new ZipArchive;	
		$ids = explode(',',$id);
		$query = DB::table('chat_shared_file');
				$i = 0;
				foreach ($ids as $idsVal) {
					   $file_ids = explode('-',$idsVal);
					if(!empty($file_ids[1])){
						if($i==0){
						 $query->where(['chat_id'=>$file_ids[0],'id'=>$file_ids[1]]);	
						}else{
							$query->orWhere(['chat_id'=>$file_ids[0],'id'=>$file_ids[1]]);
						}
					}else{
						if($i==0){
						 $query->where(['chat_id'=>$file_ids[0]]);
						}else{
							$query->orWhere(['chat_id'=>$file_ids[0]]);
						}
					}
				 $i++;		
				
				}
		$share_file = $query->pluck('file_name')->toArray(); 
		$filename ="";
		if(!empty($share_file)){
			if(count($share_file)>1){
				$filename = time().".zip";
				$zip->open($filename, ZipArchive::CREATE);
				foreach($share_file as $share_fileVal){
					$path = public_path().'/uploads/chat_share_file/'.$share_fileVal;
					if(file_exists($path)){
						$zip->addFromString(basename($path), file_get_contents($path));  
					}
				}
				$zip->close();	
			}else{
				foreach($share_file as $share_fileVal){
					$filename = public_path('uploads/chat_share_file/'.$share_fileVal);
				}
			}
		}
	    return response()->download($filename);
	}
