			} else {
				return response()->json(['status' => false, 'last_id' => '', 'last_msg' => '', 'return_view' => '']);
			}
			die;
	}
	
	public function getStudentListCreateGroup(Request $request){
		$user= Auth::user();
		$user_id = $user->id;
		$institute_id = $user->institute_id;
				
		$serach_txt =  $request->serach_txt;
		$groupchat_id =  $request->groupchat_id;
		$studentArr =  $request->studentArr;
		
		$academic_session_id =  Session::get('aSessionId');		
	    $semester_id =  Session::get('semesterId');
		
		$tutorGradesSection = DB::table('member_section')
							->join('grades', function ($join) use ($academic_session_id, $semester_id) {
								$join->on('member_section.grade_id', '=', 'grades.id')
									->where('member_section.status', 1)
									->where('member_section.academic_session_id', '=', $academic_session_id)
									->where('member_section.semester_id', '=', $semester_id);
							})
							->join('member_school', function ($join) use ($user_id, $academic_session_id, $semester_id) {
								$join->on('grades.school_id', '=', 'member_school.school_id')
									->where('member_school.user_id', $user_id)
									->where('member_school.status', 1)
									->where('member_school.academic_session_id', '=', $academic_session_id)
									->where('member_school.semester_id', '=', $semester_id);
							})
							->select(
								DB::raw('GROUP_CONCAT(DISTINCT grades.school_id) as school_id'),
								DB::raw('GROUP_CONCAT(DISTINCT member_section.grade_id) as grade_id'),
								DB::raw('GROUP_CONCAT(DISTINCT member_section.section_id) as section_id')
							)
							->where([
								'member_section.user_id' => $user_id,
								'member_section.status' => 1,
								'grades.institute_id' => $institute_id
							])
							->first();
		
		/* $tutorGradesSection = DB::table('member_section')
                        ->join('grades', 'member_section.grade_id', '=', 'grades.id')
                        ->select(DB::raw('group_concat(DISTINCT grades.school_id) as school_id'), DB::raw('group_concat(DISTINCT member_section.grade_id) as grade_id'), DB::raw('group_concat(DISTINCT member_section.section_id) as section_id'))
                        ->whereIn('grades.school_id', function($query) use($user_id) {
                            $query->select('school_id')->from('member_school')->where('user_id', $user_id);
                        })
                        ->where(['member_section.user_id'=>$user_id,'member_section.status'=>1, 'grades.institute_id' => $institute_id])
                        ->get()->first(); */

		$schoolID =  !empty($tutorGradesSection->school_id) ? explode(",",$tutorGradesSection->school_id): ''; 			
		$gradeIDArr =  !empty($tutorGradesSection->grade_id) ? explode(",",$tutorGradesSection->grade_id): ''; 			
		$sectionIDArr =  !empty($tutorGradesSection->section_id) ? explode(",",$tutorGradesSection->section_id): ''; 			
					
		$studentlist = DB::table('users')
						->select('users.id as student_id', 'users.profile_pic', 'users.fullname as student_name', 'users.is_login', 'grades.school_id', 'member_section.grade_id', 'member_section.section_id', 'member_grade.grade_name', 'member_section.section_name')
						->join('member_grade', function($join) use ($gradeIDArr,$academic_session_id,$semester_id) {
							$join->on('member_grade.user_id', '=', 'users.id')
							->where('member_grade.status', 1)
							->where('member_grade.academic_session_id', '=', $academic_session_id)
							->where('member_grade.semester_id', '=', $semester_id)
							->whereIn('member_grade.grade_id', $gradeIDArr);
						})
						->join('member_section', function($join) use ($sectionIDArr,$academic_session_id,$semester_id) {
							$join->on('member_section.user_id', '=', 'users.id')
								->where('member_section.status', 1)
								->where('member_section.academic_session_id', '=', $academic_session_id)
								->where('member_section.semester_id', '=', $semester_id)
								->whereIn('member_section.section_id', $sectionIDArr)->where('member_section.status', '=', 1);
						})
						->join('grades', function($join) use ($schoolID,$academic_session_id,$semester_id) {
							$join->on('member_grade.grade_id', '=', 'grades.id')
							->where('member_grade.status', 1)
							->where('member_grade.academic_session_id', '=', $academic_session_id)
							->where('member_grade.semester_id', '=', $semester_id)
							->whereIn('grades.school_id', array_unique($schoolID));
						})
						->where('users.role_id', '=', 3)
						->where('users.status', '=', 1)
						->where('users.institute_id', '=', $institute_id)
						->where(function ($query) use ($serach_txt) {
								$query->where('users.fullname', 'like', '%' . $serach_txt . '%')
									  ->orWhere('users.username', 'like', '%' . $serach_txt . '%')
									  ->orWhere('users.first_name', 'like', '%' . $serach_txt . '%')
									  ->orWhere('users.last_name', 'like', '%' . $serach_txt . '%');
						})
						->orderBy('users.first_name', 'ASC')
						->get();
		$group_details="";			
		$group_member="";			
		if(!empty($groupchat_id)){
			
			$group_details  = DB::table('chat_group')
									->select('group_name','group_image')
									->where('id','=',$groupchat_id)
									->where('chat_group.group_created_by', '=', $user_id)
									->where('chat_group.institute_id', '=', $institute_id)
									->where('chat_group.academic_session_id', '=', $academic_session_id)
									->where('chat_group.semester_id', '=', $semester_id)
									->first();
									
			 $group_member  = DB::table('chat_group_member')
									->select('group_id','user_id')
									->where(['group_id'=>$groupchat_id])
									->pluck('user_id')->toArray();
		}
		$data['tutor_id'] = $user_id;
		$data['group_details'] = $group_details;
		$data['group_member'] = $group_member;
		$data['studentlist'] = $studentlist;
		$data['studentArr'] = $studentArr;
		$returnHTML = view('tutor/_student_list_create_group')->with($data)->render();
        return response()->json(['status' => true,'returnHTML'=>$returnHTML,'group_details'=>$group_details]);
	}
	
	public function createGroup(Request $request){
	
		$user = Auth::user();
		$user_id = $user->id;
		$institute_id = $user->institute_id;
		$userTimeZone = !empty($user->time_zone) ? $user->time_zone : Config::get('app.timezone');
		$academic_session_id =  Session::get('aSessionId');		
	    $semester_id =  Session::get('semesterId');
		
		
	    $group_name = $request->input('group_name');
	    $cg_student = $request->input('cg-student');
	    $chatgroup_id = $request->input('chatgroup_id');
	
	    $groupfileImage = "";
	    if ($request->hasFile('groupimg')) {
            $upload_path = public_path().'/uploads/chat_share_file/';
            if (!file_exists($upload_path)) {
                mkdir($upload_path, 0777, true);
            }
	        $file = $request->file('groupimg');
			$checkFileName = $file->getClientOriginalName();
			$extension = pathinfo($checkFileName, PATHINFO_EXTENSION);
		    $groupfileImage = time().'.'.$extension;
        	try {
			   $file->move($upload_path, $groupfileImage);
			} catch (\Exception $e) {
				return response()->json(['status' =>false,'error' =>$e->getMessage()]);
			}
		}
		
		 $groupArr = array(
			'group_name' => $group_name ,
			'chat_type' => 2,
			'institute_id' => $institute_id,
			'academic_session_id' => $academic_session_id,
			'semester_id' => $semester_id,
			'group_created_by' =>$user_id,
		);
		if(!empty($groupfileImage)){
			$groupArr['group_image'] = $groupfileImage;
		}
		
		if(!empty($chatgroup_id)){
			$groups = DB::table('chat_group')->where('id', '=', $chatgroup_id)->first();
			$groupArr['updated_at'] = date('Y-m-d H:i:s');
			DB::table('chat_group')->where('id', '=', $chatgroup_id)->update($groupArr);
		    $group_Id = $chatgroup_id;
			$group_code = !empty($groups->group_id) ? $groups->group_id : ''; 
		}else{
		   $key = random_int(0, 999999);
		   $key = str_pad($key, 6, 0, STR_PAD_LEFT);
		   $group_code = base64_encode($key);
		   $groupArr['group_id'] = $group_code;
		   $groupArr['created_at'] = date('Y-m-d H:i:s');
		   $group_Id = DB::table('chat_group')->insertGetId($groupArr);
		}
	
		$group_member =array();
		if(!empty($chatgroup_id)){
			DB::table('chat_group_member')->where('group_id', '=', $chatgroup_id)->delete();
		}
		if(!empty($group_Id) && !empty($cg_student)){
			$group_member[] = array('group_id'=>$group_Id,'group_code'=>$group_code,'user_id'=>$user_id);
			foreach($cg_student as $cg_studentVal){
				
				$group_member[] = array('group_id'=>$group_Id,
										'group_code'=>$group_code,
										'user_id'=>$cg_studentVal
										);
			}
			$last_insert_Id = DB::table('chat_group_member')->insert($group_member);
		}
		
		$chatGroup = DB::table('chat_group')
							->select('id','group_name','group_image','group_id')
							->where('group_created_by',$user_id)
							->where('institute_id',$institute_id)
							->where('academic_session_id',$academic_session_id)
							->where('semester_id',$semester_id)
							->get()->all();
							
		if(!empty($chatGroup)){
			foreach($chatGroup as $key=>$chat_groupVal){
				$last_msg_info = DB::table('chat_msg as c')
								->select('c.id as chat_id', 'c.group_id', 'c.sender_id', 'c.msg', 'c.created_at','c.is_share_file','c.is_link')
								->where('c.group_id', '=', $chat_groupVal->group_id)
								->where('c.institute_id',$institute_id)
								->where('c.academic_session_id',$academic_session_id)
								->where('c.semester_id',$semester_id)
								->orderBy('created_at', 'DESC')
								->first();
				$chatGroup[$key]->chat_id = !empty($last_msg_info->chat_id) ? $last_msg_info->chat_id : '';	
				$chatGroup[$key]->msg = !empty($last_msg_info->msg) ? $last_msg_info->msg : '';	
				$chatGroup[$key]->time = !empty($last_msg_info->created_at) ? Helper::getTime(Carbon::createFromFormat('Y-m-d H:i:s', $last_msg_info->created_at, 'UTC')->setTimezone($userTimeZone)->format('h:i A')) : ''; 
			}
		}					
		$chat_group = collect($chatGroup)->sortByDesc('chat_id')->values();						
		$data['tutor_id'] = $user_id;
		$data['chat_group'] = $chat_group;
		$returnHTML = view('tutor/_chat_group_list')->with($data)->render();
        return response()->json(['status' => true,'chatgroup_id'=>$group_Id,'returnHTML'=>$returnHTML]);					
	}
	
	public function getCreatedGroup(){
		$user = Auth::user();
		$user_id = $user->id;
		$institute_id = $user->institute_id;
		$userTimeZone = !empty($user->time_zone) ? $user->time_zone : Config::get('app.timezone');
		$academic_session_id =  Session::get('aSessionId');		
	    $semester_id =  Session::get('semesterId');
		
		$chatGroup = DB::table('chat_group')
					->join('chat_group_member', function ($join) use ($user_id) {
						$join->on('chat_group_member.group_id', '=', 'chat_group.id')
							->where('chat_group_member.user_id', '=', $user_id);
					})
					->select('chat_group.id','chat_group.group_name', 'chat_group.group_image', 'chat_group.group_id', DB::raw('(SELECT SUM(chat_msg_status.is_read = 0 AND chat_msg_status.status = 0) FROM chat_msg JOIN chat_msg_status ON chat_msg_status.chat_msg_id = chat_msg.id WHERE chat_msg.group_id = chat_group.group_id AND chat_msg_status.receiver_id = "' . $user_id . '") AS unread_count'))
					->where('chat_group.institute_id',$institute_id)
					->where('chat_group.status',1)
					->where('chat_group.academic_session_id',$academic_session_id)
					->where('chat_group.semester_id',$semester_id)
					->get()
					->all();
					if (!empty($chatGroup)) {
						foreach ($chatGroup as $key => $chat_groupVal) {
							$last_msg_info = DB::table('chat_msg as c')
								->select('c.id as chat_id', 'c.group_id', 'c.sender_id', 'c.msg', 'c.created_at','c.is_share_file', 'c.is_link', 'chat_shared_file.file_type', 'chat_shared_file.file_name', 'chat_shared_file.file_mime_type', 'chat_shared_file.is_recording')
								->leftJoin('chat_shared_file', 'chat_shared_file.chat_id', '=', 'c.id')
								->where('c.group_id', '=', $chat_groupVal->group_id)
								->where('c.institute_id', '=', $institute_id)
								->where('c.academic_session_id', '=', $academic_session_id)
								->where('c.semester_id', '=', $semester_id)
								->orderBy('created_at', 'DESC')
								->first();
							$chatGroup[$key]->chat_id = !empty($last_msg_info->chat_id) ? $last_msg_info->chat_id : '';
							$chatGroup[$key]->msg = !empty($last_msg_info->msg) ? $last_msg_info->msg : '';
							$chatGroup[$key]->time = !empty($last_msg_info->created_at) ? Helper::getTime(Carbon::createFromFormat('Y-m-d H:i:s', $last_msg_info->created_at, 'UTC')->setTimezone($userTimeZone)->format('h:i A')) : ''; 
							$chatGroup[$key]->file_type = !empty($last_msg_info->file_type) ? $last_msg_info->file_type : '';
							$chatGroup[$key]->file_name = !empty($last_msg_info->file_name) ? $last_msg_info->file_name : '';
							$chatGroup[$key]->file_mime_type = !empty($last_msg_info->file_mime_type) ? $last_msg_info->file_mime_type : '';
							$chatGroup[$key]->is_recording = !empty($last_msg_info->is_recording) ? $last_msg_info->is_recording : '';
							$chatGroup[$key]->unread_count = $chat_groupVal->unread_count;
						}
					}
		
		$chat_group = collect($chatGroup)->sortByDesc('chat_id')->values();					
		$data['tutor_id'] = $user_id;
		$data['chat_group'] = $chat_group;
		$returnHTML = view('tutor/_chat_group_list')->with($data)->render();
		return response()->json(['status' => true,'returnHTML'=>$returnHTML]);					
	}

