    public function deleteChatGroups(Request $request){
	    $cgroup_id = $request->cgroup_id;
	    $institute_id = $request->institute_id;
	    $checkgroups = DB::table('chat_group')->where(['chat_group.group_created_by'=>Auth::user()->id,'chat_group.id'=>$cgroup_id,'chat_group.institute_id'=>$institute_id])->first();
	    if(!empty($checkgroups)){
			DB::table('chat_group')
			->where(['chat_group.group_created_by'=>Auth::user()->id,'chat_group.id'=>$cgroup_id])
			->update(['status' =>0, 'updated_at' => date('Y-m-d H:i:s')]);
		 return response()->json(['status'=> true,'message' =>'Group deleted successfully']);	
		}else{
			return response()->json(['status'=> false,'message' =>'this group not exists']);
		}
    }

