			$userTimeZone = $now->timezone->getName();
			//$userTimeZone = !empty($user->time_zone) ? $user->time_zone : Config::get('app.timezone');
			
			
			$active_group_id = $request->active_group_id;
			$gradesection_group_id = $request->gradesection_group_id;
			$page = $request->page; 
			$page = $request->page ? $request->page : 1;
			$limit = 10;
			$grpmsgs = DB::table('chat_msg as c')
					->select('c.id as chat_id', 'c.group_id', 'c.sender_id', 'c.msg','c.created_at', 'c.is_share_file', 'c.is_link','c.file_type','c.mime_type','c.is_reply','c.reply_message_id','c.reply_share_message_id','users.id','users.profile_pic','users.fullname as sender_name')
					->join('chat_msg_status', 'c.id', '=', 'chat_msg_status.chat_msg_id')
					->join('users', 'users.id', '=', 'c.sender_id')
					->where('c.group_id', '=', $gradesection_group_id)
					->orderBy('chat_id', 'DESC')
					->limit($limit)
					->offset(($page - 1) * $limit)
					->get()
