											<li><a href="javascript:void(0)" onclick="removeChatMessage('.$v1->chat_id.','.$chat_shared_file_id.')">'.__('messages.remove').'</a></li>
											</ul>
											'. $msgText . '
											<div class="corner"></div>
											<span>' . $date_time. "</span></div></div>";	
					}
                }
			}
			
			return response()->json(['status' => true,'return_view' => $return_view]);
			} else {
				return response()->json(['status' => false,'return_view' => 'Chat history no more available']);
			}
		}
		
