	public function getConferenceTool(Request $request){
		$user = Auth::user();
		$userTimeZone = !empty($user->time_zone) ? $user->time_zone : Config::get('app.timezone');
		$data['conferenceToolData'] = DB::table('session_meeting_url')
							->select('zoom_url','googlemeet_url', 'microsoftteam_url',)
							->where(['tutor_id'=>$user->id,'institute_id'=>$user->institute_id])
							->first();
		$returnHTML = view('tutor/_conference_tool')->with($data)->render();
        return response()->json(['status' => true,'returnHTML'=>$returnHTML]);
        die;
	}
	
