	//b2c chat function start from here
	public function getUserListB2C(Request $request){
		$user = Auth::user();
		$institute_id = $user->institute_id;
		$user_id = $user->id;
		$userTimeZone = !empty($user->time_zone) ? $user->time_zone : Config::get('app.timezone');
		$data['active_group_id'] = $request->active_group_id;
		$data['user_id'] = $user_id; 
		$data['userTimeZone'] = $userTimeZone; 
		$data['groups'] = DB::table('chat_group')
							->select('users.id','users.fullname', 'users.profile_pic','users.is_login','chat_group.group_id', 'chat_group.student_id','last_msg.msg','chat_shared_file.file_type','chat_shared_file.file_name','chat_shared_file.file_mime_type','chat_shared_file.is_recording','last_msg.created_at')
							->join('users', 'chat_group.student_id', '=', 'users.id')
							->leftJoin('chat_msg as last_msg', function ($join) {
								$join->on('last_msg.group_id', '=', 'chat_group.group_id')
									 ->whereRaw('last_msg.id = (SELECT id FROM chat_msg WHERE group_id = chat_group.group_id ORDER BY id DESC LIMIT 1)');
							})
							 ->leftJoin('chat_shared_file', function ($join) {
								$join->on('chat_shared_file.chat_id', '=', 'last_msg.id')
									->whereExists(function ($query) {
										$query->select(DB::raw(1))
											->from('chat_shared_file')
											->whereRaw('chat_shared_file.chat_id = last_msg.id')
											->orderByDesc('chat_shared_file.id')
											->limit(1);
									});
							})
							->where('chat_group.tutor_id', $user_id)
							->groupBy('chat_group.group_id')
							->orderByRaw('IFNULL(last_msg.created_at, 0) DESC')
							->get();
							
		$returnHTML = view('tutor/_b2c_user_list')->with($data)->render();
        return response()->json(['status' => true,'returnHTML'=>$returnHTML]);
        die;
		
	}
	
	public function getB2CUserListPage(Request $request){
		$user = Auth::user();
		$institute_id = $user->institute_id;
		$user_id = $user->id;
		$userTimeZone = !empty($user->time_zone) ? $user->time_zone : Config::get('app.timezone');
		//$data['active_group_id'] = $request->active_group_id;
		$search_txt = $request->search_txt;
		$data['user_id'] = $user_id; 
		$data['groups'] = DB::table('chat_group')
							->select('users.id','users.fullname', 'users.profile_pic','users.is_login','chat_group.group_id', 'chat_group.student_id','last_msg.msg', DB::raw("DATE_FORMAT(CONVERT_TZ(last_msg.created_at, 'UTC', '{$userTimeZone}'), '%d-%m-%Y %h:%i %p') as date_time"))
							->join('users', 'chat_group.student_id', '=', 'users.id')
							->leftJoin('chat_msg as last_msg', function ($join) {
								$join->on('last_msg.group_id', '=', 'chat_group.group_id')
									 ->whereRaw('last_msg.id = (SELECT id FROM chat_msg WHERE group_id = chat_group.group_id ORDER BY id DESC LIMIT 1)');
							})
							->where('chat_group.tutor_id', $user_id)
							->where(function ($query) use ($search_txt) {
								if(!empty($search_txt)){
									$query->orWhere('users.fullname', 'like', '%' . $search_txt . '%');
									$query->orWhere('users.first_name', 'like', '%' . $search_txt . '%');
								} 
							})
							->orderBy('users.first_name', 'ASC')
							->orderByRaw('IFNULL(last_msg.created_at, 0) DESC')
							->get();
		$returnHTML = view('tutor/_message_forward_b2c_user_list_page')->with($data)->render();
        return response()->json(['status' => true,'returnHTML'=>$returnHTML]);
        die;
	}

	// chat wigdth	 section start
	public function getchatwidgetUserlist(Request $request){
		
		$user = Auth::user();
		$user_id = $user->id;
		$institute_id = $user->institute_id;
		$academic_session_id =  Session::get('aSessionId');		
	    $semester_id =  Session::get('semesterId');
		$tutorName = $user->fullname;
		$now = Carbon::now();
		$userTimeZone = $now->timezone->getName();
		//$userTimeZone = !empty($user->time_zone) ? $user->time_zone : Config::get('app.timezone');
		
		
		$tutorGradeSection = DB::table('member_section')
							->select('member_section.user_id as tutor_id', 'grades.school_id', 'member_section.grade_id', 'member_section.section_id', 'school_name', DB::raw('CONCAT(grades.grade, " (", section.section, ")") AS grade_section'))
							->Join('grades', function ($join) use ($academic_session_id, $semester_id) {
							$join->on('grades.id', '=', 'member_section.grade_id')
								->where('member_section.academic_session_id', $academic_session_id)
								->where('member_section.semester_id', $semester_id)
								->where('member_section.status', 1);
							})
							->join('school', 'grades.school_id', '=', 'school.id')
							->join('section', 'member_section.section_id', '=', 'section.id')
							->where('member_section.user_id', '=', $user_id)
							->where('school.institute_id', '=', $institute_id)
							->where('school.status', '=', 1)
							->get();
							
		
		$mainGroupArr =array();
		$studentsArr= array();	
		$groupsArr = array();
			
		if(!empty($tutorGradeSection)){
			foreach ($tutorGradeSection as $key => $tutorGradeSectionVal) {
				
				$main_group_id = base64_encode($tutorGradeSectionVal->school_id.'-'.$tutorGradeSectionVal->grade_id.'-'.$tutorGradeSectionVal->section_id.'-'.$tutorGradeSectionVal->tutor_id);
				$last_msg_info = DB::table('chat_msg as c')
								->select('c.id as chat_id', 'c.group_id', 'c.sender_id', 'c.msg','c.created_at','c.is_share_file','c.is_link','chat_shared_file.file_type','chat_shared_file.file_name','chat_shared_file.file_mime_type','chat_shared_file.is_recording','chat_shared_file.recording_duration')
								->leftJoin('chat_shared_file','chat_shared_file.chat_id', '=', 'c.id')
								->where('c.group_id', '=', $main_group_id)
								->where('c.institute_id', $institute_id)
								->where('c.academic_session_id', $academic_session_id)
								->where('c.semester_id', $semester_id)
								->orderBy('c.id', 'DESC')
								->first();
				$mainGroupArr[$key] = new \stdClass(); //the magic see new object member created on the fly without warning.
				$mainGroupArr[$key]->id = $tutorGradeSectionVal->tutor_id;
				$mainGroupArr[$key]->main_group_id = $main_group_id;
				$mainGroupArr[$key]->group_name = $tutorGradeSectionVal->grade_section;
				$mainGroupArr[$key]->group_image = url('/').'/public/uploads/icon/icon_1644316802.png';
				$mainGroupArr[$key]->school_id = $tutorGradeSectionVal->school_id;	
				$mainGroupArr[$key]->grade_id =  $tutorGradeSectionVal->grade_id;
				$mainGroupArr[$key]->section_id = $tutorGradeSectionVal->section_id;
				$mainGroupArr[$key]->chat_id = !empty($last_msg_info->chat_id) ? $last_msg_info->chat_id : '';	
				$mainGroupArr[$key]->msg = !empty($last_msg_info->msg) ? $last_msg_info->msg : '';	
				$mainGroupArr[$key]->time = !empty($last_msg_info->created_at) ? Helper::getTime(Carbon::createFromFormat('Y-m-d H:i:s', $last_msg_info->created_at, 'UTC')->setTimezone($userTimeZone)->format('h:i A')) : ''; 	
				$mainGroupArr[$key]->file_type = !empty($last_msg_info->file_type) ? $last_msg_info->file_type : '';	
				$mainGroupArr[$key]->file_name = !empty($last_msg_info->file_name) ? $last_msg_info->file_name : '';	
				$mainGroupArr[$key]->file_mime_type = !empty($last_msg_info->file_mime_type) ? $last_msg_info->file_mime_type : '';	
				$mainGroupArr[$key]->is_recording = !empty($last_msg_info->is_recording) ? $last_msg_info->is_recording : '';
				$mainGroupArr[$key]->recording_duration = !empty($last_msg_info->recording_duration) ? $last_msg_info->recording_duration : '';

				
				$groupsArr[] = array('institute_id'=>$institute_id,
									 'group_id'=>$main_group_id,	
									 'group_name'=>$tutorGradeSectionVal->grade_section.'-('.ucfirst($tutorName).')',
									 'group_image'=>url('/').'/public/uploads/icon/icon_1644316802.png',										 
									 'chat_type'=>2,	
									 'status'=>1,	
									 'created_at' => date('Y-m-d H:i:s'),
									);
									
				$students = DB::table('users')
								->select('users.id as student_id', 'users.fullname', 'users.profile_pic', 'users.is_login', 'grades.school_id', 'member_section.grade_id', 'member_section.section_id')
								->join('member_section', function ($join) use ($tutorGradeSectionVal,$academic_session_id,$semester_id){
									$join->on('member_section.user_id', '=', 'users.id')
										->where('member_section.status', '=', 1)
										->where('member_section.academic_session_id', $academic_session_id)
										->where('member_section.semester_id', $semester_id)
										->where('member_section.section_id', '=', $tutorGradeSectionVal->section_id);
								})
								->join('member_grade', function ($join) use ($tutorGradeSectionVal,$academic_session_id,$semester_id) {
									$join->on('member_grade.user_id', '=', 'users.id')
										->where('member_grade.academic_session_id', $academic_session_id)
										->where('member_grade.semester_id', $semester_id)
										->where('member_grade.status', '=', 1)
										->where('member_grade.grade_id', '=', $tutorGradeSectionVal->grade_id);
								})
								->join('grades', function ($join) use ($tutorGradeSectionVal) {
									$join->on('grades.id', '=', 'member_grade.grade_id')
										->where('grades.school_id', '=', $tutorGradeSectionVal->school_id);
								})
								->where('users.role_id', '=', 3)
								->where('users.institute_id', '=', $institute_id)
								->orderBy('users.first_name', 'ASC')
								->get()
								->all();
							
				if(!empty($students)){
					foreach ($students as $key => $studentsVal) {
						$groupID =  base64_encode($studentsVal->school_id.'-'.$studentsVal->grade_id.'-'.$studentsVal->section_id.'-'.$studentsVal->student_id.'-'.$user_id);
						$last_msg_info = DB::table('chat_msg as c')
										->select('c.id as chat_id', 'c.group_id', 'c.sender_id', 'c.msg', 'c.created_at','c.is_share_file','c.is_link','chat_shared_file.file_type','chat_shared_file.file_name','chat_shared_file.file_mime_type','chat_shared_file.is_recording','chat_shared_file.recording_duration')
										->leftJoin('chat_shared_file','chat_shared_file.chat_id', '=', 'c.id')
										->where('c.group_id', '=', $groupID)
										->where('c.institute_id', $institute_id)
										->where('c.academic_session_id', $academic_session_id)
										->where('c.semester_id', $semester_id)
										->orderBy('c.id', 'DESC')
										->first();
						$studentsVal->main_group_id = '';	
						$studentsVal->school_id = $tutorGradeSectionVal->school_id;	
						$studentsVal->grade_id =  $tutorGradeSectionVal->grade_id;
						$studentsVal->section_id = $tutorGradeSectionVal->section_id;	
						$studentsVal->chat_id = !empty($last_msg_info->chat_id) ? $last_msg_info->chat_id : '';	
						$studentsVal->msg = !empty($last_msg_info->msg) ? $last_msg_info->msg : '';	
						$studentsVal->time = !empty($last_msg_info->created_at) ? Helper::getTime(Carbon::createFromFormat('Y-m-d H:i:s', $last_msg_info->created_at, 'UTC')->setTimezone($userTimeZone)->format('h:i A')) : ''; 	
						$studentsVal->group_id = $groupID;	
						$studentsVal->file_type = !empty($last_msg_info->file_type) ? $last_msg_info->file_type : '';	
						$studentsVal->file_name = !empty($last_msg_info->file_name) ? $last_msg_info->file_name : '';	
						$studentsVal->file_mime_type = !empty($last_msg_info->file_mime_type) ? $last_msg_info->file_mime_type : '';	
						$studentsVal->is_recording = !empty($last_msg_info->is_recording) ? $last_msg_info->is_recording : '';	
						$studentsVal->recording_duration = !empty($last_msg_info->recording_duration) ? $last_msg_info->recording_duration : '';	
						$studentsArr[] = $studentsVal;
						
						$groupsArr[] = array('institute_id'=>$institute_id,
										 'group_id'=>$groupID,	
										 'group_name'=>ucfirst($tutorName).'-'.ucfirst($studentsVal->fullname),	
										 'group_image'=>!empty($studentsVal->profile_pic) ? $studentsVal->profile_pic :'',	
										 'chat_type'=>1,	
										 'status'=>1,	
										 'created_at' => date('Y-m-d H:i:s'),
										);
					}
				}
					
			}
		}
		if(!empty($groupsArr)){
			DB::table('chat_group')->insertOrIgnore($groupsArr);
		}
		$mainGroup = array_merge($studentsArr,$mainGroupArr);
		$studentData = collect($mainGroup)->sortByDesc('chat_id')->values();
		
		
		$data['studentData'] = $studentData; 
		$data['user_id'] = $user_id; 
		$returnHTML = view('tutor/_chatwidget_userlist')->with($data)->render();
        return response()->json(['status' => true,'returnHTML'=>$returnHTML,'studentData'=>$studentData]);
        die;
	}
	
	public function getchatwidgetGroupChatlist(Request $request){
		
		$user = Auth::user();
		$user_id = $user->id;
		$institute_id = $user->institute_id;
		$userTimeZone = !empty($user->time_zone) ? $user->time_zone : Config::get('app.timezone');
		$academic_session_id =  Session::get('aSessionId');		
	    $semester_id =  Session::get('semesterId');
		
		$chatGroup = DB::table('chat_group')
					->join('chat_group_member', function ($join) use ($user_id) {
						$join->on('chat_group_member.group_id', '=', 'chat_group.id')
							->where('chat_group_member.user_id', '=', $user_id);
					})
					->select('chat_group.id','chat_group.group_name', 'chat_group.group_image', 'chat_group.group_id', DB::raw('(SELECT SUM(chat_msg_status.is_read = 0 AND chat_msg_status.status = 0) FROM chat_msg JOIN chat_msg_status ON chat_msg_status.chat_msg_id = chat_msg.id WHERE chat_msg.group_id = chat_group.group_id AND chat_msg_status.receiver_id = "' . $user_id . '") AS unread_count'))
					->where('chat_group.institute_id',$institute_id)
					->where('chat_group.status',1)
					->where('chat_group.academic_session_id',$academic_session_id)
					->where('chat_group.semester_id',$semester_id)
					->get()
					->all();
					if (!empty($chatGroup)) {
						foreach ($chatGroup as $key => $chat_groupVal) {
							$last_msg_info = DB::table('chat_msg as c')
								->select('c.id as chat_id', 'c.group_id', 'c.sender_id', 'c.msg', 'c.created_at','c.is_share_file', 'c.is_link', 'chat_shared_file.file_type', 'chat_shared_file.file_name', 'chat_shared_file.file_mime_type', 'chat_shared_file.is_recording')
								->leftJoin('chat_shared_file', 'chat_shared_file.chat_id', '=', 'c.id')
								->where('c.group_id', '=', $chat_groupVal->group_id)
								->where('c.institute_id', '=', $institute_id)
								->where('c.academic_session_id', '=', $academic_session_id)
								->where('c.semester_id', '=', $semester_id)
								->orderBy('created_at', 'DESC')
								->first();
							$chatGroup[$key]->chat_id = !empty($last_msg_info->chat_id) ? $last_msg_info->chat_id : '';
							$chatGroup[$key]->msg = !empty($last_msg_info->msg) ? $last_msg_info->msg : '';
							$chatGroup[$key]->time = !empty($last_msg_info->created_at) ? Helper::getTime(Carbon::createFromFormat('Y-m-d H:i:s', $last_msg_info->created_at, 'UTC')->setTimezone($userTimeZone)->format('h:i A')) : ''; 
							$chatGroup[$key]->file_type = !empty($last_msg_info->file_type) ? $last_msg_info->file_type : '';
							$chatGroup[$key]->file_name = !empty($last_msg_info->file_name) ? $last_msg_info->file_name : '';
							$chatGroup[$key]->file_mime_type = !empty($last_msg_info->file_mime_type) ? $last_msg_info->file_mime_type : '';
							$chatGroup[$key]->is_recording = !empty($last_msg_info->is_recording) ? $last_msg_info->is_recording : '';
							$chatGroup[$key]->unread_count = $chat_groupVal->unread_count;
						}
					}
		
		$chat_group = collect($chatGroup)->sortByDesc('chat_id')->values();					
		$data['tutor_id'] = $user_id;
		$data['chat_group'] = $chat_group;
		$returnHTML = view('tutor/_chatwidget_userlist_group')->with($data)->render();
		return response()->json(['status' => true,'returnHTML'=>$returnHTML]);	
	}
	
	public function getchatwidgetB2CUserlist(Request $request){
		
		$user = Auth::user();
		$institute_id = $user->institute_id;
		$user_id = $user->id;
		$userTimeZone = empty($user->time_zone) ? $user->time_zone : Config::get('app.timezone');
		$data['active_group_id'] = $request->active_group_id;
		$data['user_id'] = $user_id; 
		$data['groups'] = DB::table('chat_group')
							->select('users.id','users.fullname', 'users.profile_pic','users.is_login','chat_group.group_id', 'chat_group.student_id','last_msg.msg','chat_shared_file.file_type','chat_shared_file.file_name','chat_shared_file.file_mime_type','chat_shared_file.is_recording',DB::raw("DATE_FORMAT(CONVERT_TZ(last_msg.created_at, 'UTC', '{$userTimeZone}'),'%d-%m-%Y %h:%i %p') as date_time"))
							->join('users', 'chat_group.student_id', '=', 'users.id')
							->leftJoin('chat_msg as last_msg', function ($join) {
								$join->on('last_msg.group_id', '=', 'chat_group.group_id')
									 ->whereRaw('last_msg.id = (SELECT id FROM chat_msg WHERE group_id = chat_group.group_id ORDER BY id DESC LIMIT 1)');
							})
							 ->leftJoin('chat_shared_file', function ($join) {
								$join->on('chat_shared_file.chat_id', '=', 'last_msg.id')
									->whereExists(function ($query) {
										$query->select(DB::raw(1))
											->from('chat_shared_file')
											->whereRaw('chat_shared_file.chat_id = last_msg.id')
											->orderByDesc('chat_shared_file.id')
											->limit(1);
									});
							})
							->where('chat_group.tutor_id', $user_id)
							->groupBy('chat_group.group_id')
							->orderByRaw('IFNULL(last_msg.created_at, 0) DESC')
							->get();
		$returnHTML = view('tutor/_chatwidget_userlist_b2c')->with($data)->render();
        return response()->json(['status' => true,'returnHTML'=>$returnHTML]);
        die;
	}
	
	public function getChatBoxWindow(Request $request) {
        $user = Auth::user();
		$user_id = $user->id;
		$institute_id = $user->institute_id;
		$academic_session_id =  Session::get('aSessionId');		
	    $semester_id =  Session::get('semesterId');
		
        $student_id = $request->get('student_id');
        $active_group_id = $request->get('active_group_id');
        $group_type = $request->get('group_type');
       // $is_click = $request->get('is_click');
		
        $data['id'] = $request->get('id');
        $data['active_group_id'] = $active_group_id;
	    $data['group_type'] = $group_type;
		
		$now = Carbon::now();
		$userTimeZone = $now->timezone->getName();
		$currentDateTime = Carbon::now($userTimeZone)->format('Y-m-d H:i:s');
		$utcCurrentDateTime = Carbon::createFromFormat('Y-m-d H:i:s',trim($currentDateTime), $userTimeZone)->setTimezone('UTC')->format('Y-m-d H:i:s');
		
			if ($active_group_id) {
				$result = DB::table('chat_msg_status')
					->select(DB::raw('group_concat(chat_msg.id) as message_id'))
					->join('chat_msg', 'chat_msg.id', '=', 'chat_msg_status.chat_msg_id')
					->where('receiver_id', $user_id)
					->where('chat_msg.group_id', $active_group_id)
					->where('chat_msg.institute_id', $institute_id)
					->where('chat_msg.academic_session_id', $academic_session_id)
					->where('chat_msg.semester_id', $semester_id)
					->where('chat_msg_status.is_read', 0)
					->first();

				if ($result && !empty($result->message_id)) {
					$message_ids = explode(',', $result->message_id);

					DB::table('chat_msg_status')
						->whereIn('chat_msg_id', $message_ids)
						->where('receiver_id', $user_id)
						->update([
							'is_read' => 1,
							'status' => 1,
							'updated_at' => $utcCurrentDateTime
						]);
				} 
			}
			
		$data['conversion'] = DB::table('chat_msg as c')
						->select('c.id as chat_id', 'c.group_id', 'c.sender_id', 'c.msg',DB::raw("DATE_FORMAT(CONVERT_TZ(c.created_at, 'UTC', '{$userTimeZone}'),'%d-%m-%Y %h:%i %p') as date_time"),'c.is_share_file', 'c.is_link','c.is_meet_in_classroom','c.file_type','c.mime_type','c.is_reply','c.reply_message_id','c.reply_share_message_id','c.is_forward','c.track_duration','c.is_name_header','users.id','users.profile_pic','users.fullname as sender_name')
						->Join('users', 'users.id', '=', 'c.sender_id')
						->where('c.group_id', '=', $active_group_id)
						->where('c.institute_id', '=', $institute_id)
						->where('c.academic_session_id', '=', $academic_session_id)
						->where('c.semester_id', '=', $semester_id)
						->orderBy('chat_id', 'DESC')
						->limit(10)
						->get()
						->reverse();
						
						
		$result = DB::table('chat_msg_status')
				->where('receiver_id', $user_id)
				->where('chat_msg_status.is_read', 0)
				->selectRaw('SUM(CASE WHEN chat_msg_type = 1 THEN 1 ELSE 0 END) AS count_type_1, 
							 SUM(CASE WHEN chat_msg_type = 2 THEN 1 ELSE 0 END) AS count_type_2, 
							 SUM(CASE WHEN chat_msg_type = 3 THEN 1 ELSE 0 END) AS count_type_3')
				->first();
			$total_gs_message_count = $result->count_type_1 ?? 0;
			$total_group_message_count = $result->count_type_2 ?? 0;
			$total_b2c_message_count = $result->count_type_3 ?? 0;
			$total_message_count = $total_gs_message_count + $total_group_message_count + $total_b2c_message_count;
			
		$returnHTML = view('tutor/chat_box')->with($data)->render();
        return response()->json(['status' => true,
								'str_chatbox' => $returnHTML,
								'chatboxmsgid'=>base64_decode($active_group_id),
								'total_message_count'=>$total_message_count,
								'total_gs_message_count'=>$total_gs_message_count,
								'total_group_message_count'=>$total_group_message_count,
								'total_b2c_message_count'=>$total_b2c_message_count,
								'group_type'=>$group_type
								]);
        die;
    }
	
	public function sendMessageChatWidget(Request $request) {
      		
		$user = Auth::user();
		$user_id = $user->id;
		$institute_id = $user->institute_id;
		$academic_session_id =  Session::get('aSessionId');		
	    $semester_id =  Session::get('semesterId');
		
		$now = Carbon::now();
		$userTimeZone = $now->timezone->getName();
				
		$receiver_id = $request->input('receiver_id');
		$group_type = $request->input('group_type');
		$active_group_id = $request->input('active_group_id');
		$update_message_id = $request->input('update_message_id');
		$message = trim($request->input('msg'));
		$msg_date_time = date('d-m-Y h:i a',strtotime($request->input('date_time')));
					
		$currentDateTime = Carbon::now($userTimeZone)->format('Y-m-d H:i:s');
		$utcCurrentDateTime = Carbon::createFromFormat('d-m-Y h:i a',trim($msg_date_time), $userTimeZone)->setTimezone('UTC')->format('Y-m-d H:i:s');

		
		if($group_type =='gradesection'){
			
			$gradeSectionArr = explode("_",$receiver_id);
			
			$groupMember = DB::table('member_section')
							->join('member_school', function ($join) use ($gradeSectionArr) {
								$join->on('member_school.user_id', '=', 'member_section.user_id')
									 ->where('member_school.school_id', '=', $gradeSectionArr[0]);
							})
							->join('member_grade', function ($join) {
								$join->on('member_grade.user_id', '=', 'member_section.user_id')
									 ->where('member_grade.status', '=', 1);
							})
							->join('users', function ($join) use ($institute_id) {
								$join->on('member_school.user_id', '=', 'users.id')
									 ->where('users.role_id', '=', 3)
									 ->where('users.institute_id', '=', $institute_id);
							})
							->select('member_section.user_id')
							->where([
								['member_section.grade_id', '=', $gradeSectionArr[1]],
								['member_section.section_id', '=', $gradeSectionArr[2]],
								['member_section.status', '=', 1],
								['member_school.status', '=', 1],
								['member_section.user_id', '!=', $user_id],
							])
							->pluck('user_id');
							
					$senderArr = array(
								'group_id' =>$active_group_id,
								'sender_id' => $user_id ,
								'institute_id' => $institute_id ,
								'academic_session_id' => $academic_session_id,
								'semester_id' => $semester_id,
								'msg' => $message,
								'file_type' => 0,
								'is_name_header' =>1,
								'status' => 1,
								'created_at' => $utcCurrentDateTime,
							);
					$insert_Id = DB::table('chat_msg')->insertGetId($senderArr);
				
					$chatMsgStatus = array();
					
					if($insert_Id){
						foreach($groupMember as $key=>$recevierIdArrVal){
							$chatMsgStatus[] = array(
