						->join('users', 'users.id', '=', 'c.sender_id')
						->where('c.group_id', '=', $active_group_id)
						->where('c.sender_id', '=', $user_id)
						->where('c.institute_id', '=', $institute_id)
						->where('c.academic_session_id', '=', $academic_session_id)
						->where('c.semester_id', '=', $semester_id)
						->orderBy('chat_id', 'DESC')
						->first();
						
		$date_time = Helper::getDatetime($last_msg_info->date_time);
		$chat_id = !empty($last_msg_info->chat_id) ? $last_msg_info->chat_id :'' ;
		$is_header_name = !empty($last_msg_info->is_header_name) ? '<span class="namecls">'.$last_msg_info->sender_name.'</span>' :'' ;
				
